    /// <summary>
    /// Compares two model dump JSON files and returns detected resource-level changes.
    /// </summary>
    /// <param name="workingJson">Path to the working-copy dump JSON.</param>
    /// <param name="headJson">Path to the HEAD dump JSON.</param>
    /// <returns>Collection of model changes.</returns>
    public static List<MendixModelChange> CompareDumps(string workingJson, string headJson)
    {
        using var workingDocument = ParseDump(workingJson);
        using var headDocument = ParseDump(headJson);

        var workingSnapshot = BuildSnapshot(workingDocument.RootElement);
        var headSnapshot = BuildSnapshot(headDocument.RootElement);
        var changeMap = new Dictionary<string, MutableResourceChange>(StringComparer.OrdinalIgnoreCase);

        foreach (var (resourceId, resource) in workingSnapshot.ResourcesById)
        {
            if (!headSnapshot.ResourcesById.ContainsKey(resourceId))
            {
                changeMap[resourceId] = new MutableResourceChange("Added", resource);
            }
        }

        foreach (var (resourceId, resource) in headSnapshot.ResourcesById)
        {
            if (!workingSnapshot.ResourcesById.ContainsKey(resourceId))
            {
                changeMap[resourceId] = new MutableResourceChange("Deleted", resource);
            }
        }

        foreach (var (resourceId, workingResource) in workingSnapshot.ResourcesById)
        {
            if (!headSnapshot.ResourcesById.TryGetValue(resourceId, out var headResource))
            {
                continue;
            }

            var semanticallyEqual = ElementsSemanticallyEqual(workingResource.Object, headResource.Object);
            var hasFlowSpecificDelta = semanticallyEqual &&
                                       IsFlowModelType(workingResource.ModelType) &&
                                       !string.IsNullOrWhiteSpace(BuildMicroflowActionDeltaDetails(
                                           workingResource.Object,
                                           headResource.Object));

            if (semanticallyEqual && !hasFlowSpecificDelta)
            {
                continue;
            }

            var modified = EnsureModifiedChange(changeMap, resourceId, workingResource);
            if (!semanticallyEqual)
            {
                modified.DirectDetails = MergeDetailTexts(
                    modified.DirectDetails,
                    BuildModificationDetails(headResource.Object, workingResource.Object));
            }
        }

        AddNestedOwnershipChanges(
            changeMap,
            workingSnapshot,
            headSnapshot,
            workingSnapshot.ObjectsById.Keys.Except(headSnapshot.ObjectsById.Keys, StringComparer.OrdinalIgnoreCase),
            "Added",
            useWorkingSnapshot: true);

        AddNestedOwnershipChanges(
            changeMap,
            workingSnapshot,
            headSnapshot,
            headSnapshot.ObjectsById.Keys.Except(workingSnapshot.ObjectsById.Keys, StringComparer.OrdinalIgnoreCase),
            "Deleted",
            useWorkingSnapshot: false);

        var modifiedObjectIds = workingSnapshot.ObjectsById.Keys
            .Intersect(headSnapshot.ObjectsById.Keys, StringComparer.OrdinalIgnoreCase)
            .Where(objectId => !ElementsSemanticallyEqual(workingSnapshot.ObjectsById[objectId], headSnapshot.ObjectsById[objectId]));

        AddNestedOwnershipChanges(
            changeMap,
            workingSnapshot,
            headSnapshot,
            modifiedObjectIds,
            "Modified",
            useWorkingSnapshot: true);

        AddResourceSpecificDetails(changeMap, workingSnapshot, headSnapshot);

        return changeMap.Values
            .Select(ToModelChange)
            .OrderBy(change => change.ElementType, StringComparer.OrdinalIgnoreCase)
            .ThenBy(change => change.ElementName, StringComparer.OrdinalIgnoreCase)
            .ThenBy(change => change.ChangeType, StringComparer.OrdinalIgnoreCase)
            .ToList();
    }

    private static void AddNestedOwnershipChanges(
        Dictionary<string, MutableResourceChange> changeMap,
        DumpSnapshot workingSnapshot,
        DumpSnapshot headSnapshot,
        IEnumerable<string> changedObjectIds,
        string nestedChangeType,
        bool useWorkingSnapshot)
    {
        var ownerSnapshot = useWorkingSnapshot ? workingSnapshot : headSnapshot;

        foreach (var objectId in changedObjectIds)
        {
            if (ownerSnapshot.ResourcesById.ContainsKey(objectId))
            {
                continue;
            }

            if (!IsSemanticNestedObjectChange(workingSnapshot, headSnapshot, objectId, nestedChangeType))
            {
                continue;
            }

            var ownerResourceId = ResolveOwningResourceId(ownerSnapshot, objectId);
            if (string.IsNullOrWhiteSpace(ownerResourceId))
            {
                continue;
            }

            var ownerDescriptor = ResolveOwnerDescriptor(ownerResourceId, workingSnapshot, headSnapshot);
            if (ownerDescriptor is null)
            {
                continue;
            }

            if (changeMap.TryGetValue(ownerResourceId, out var existingHardChange) &&
                existingHardChange.ChangeType is "Added" or "Deleted")
            {
                continue;
            }

            var modified = EnsureModifiedChange(changeMap, ownerResourceId, ownerDescriptor);
            modified.NestedChanges.Increment(nestedChangeType);
        }
    }

    private static MutableResourceChange EnsureModifiedChange(
        Dictionary<string, MutableResourceChange> changeMap,
        string resourceId,
        ResourceDescriptor descriptor)
    {
        if (changeMap.TryGetValue(resourceId, out var existing))
        {
            if (existing.ChangeType is "Added" or "Deleted")
            {
                return existing;
            }

            existing.ChangeType = "Modified";
            existing.Descriptor = descriptor;
            return existing;
        }

        var created = new MutableResourceChange("Modified", descriptor);
        changeMap[resourceId] = created;
        return created;
    }

    private static MendixModelChange ToModelChange(MutableResourceChange change)
    {
        var details = ShouldSuppressNestedChangeSummary(change.Descriptor.ElementType)
            ? change.DirectDetails
            : MergeDetailTexts(change.DirectDetails, change.NestedChanges.ToDetailText());
        return new MendixModelChange(
            change.ChangeType,
            change.Descriptor.ElementType,
            change.Descriptor.ElementName,
            details);
    }

    private static bool ShouldSuppressNestedChangeSummary(string? elementType)
    {
        return string.Equals(elementType, "Entity", StringComparison.OrdinalIgnoreCase) ||
               string.Equals(elementType, NonPersistentEntityElementType, StringComparison.OrdinalIgnoreCase) ||
               string.Equals(elementType, "Association", StringComparison.OrdinalIgnoreCase);
    }

    private static void AddResourceSpecificDetails(
        Dictionary<string, MutableResourceChange> changeMap,
        DumpSnapshot workingSnapshot,
        DumpSnapshot headSnapshot)
    {
        foreach (var (resourceId, resourceChange) in changeMap)
        {
            workingSnapshot.ResourcesById.TryGetValue(resourceId, out var workingDescriptor);
            headSnapshot.ResourcesById.TryGetValue(resourceId, out var headDescriptor);
            var referenceDescriptor = workingDescriptor ?? headDescriptor;
            if (referenceDescriptor is null)
            {
                continue;
            }

            var resourceSpecificDetails = BuildResourceSpecificDetails(
                resourceChange.ChangeType,
                workingDescriptor,
                headDescriptor,
                workingSnapshot,
                headSnapshot);

            if (ShouldOverrideGenericResourceDetails(referenceDescriptor.ModelType))
            {
                resourceChange.DirectDetails = resourceSpecificDetails;
                continue;
            }

            resourceChange.DirectDetails = MergeDetailTexts(resourceChange.DirectDetails, resourceSpecificDetails);
        }
    }

    private static bool ShouldOverrideGenericResourceDetails(string modelType)
    {
        return string.Equals(modelType, DomainEntityModelType, StringComparison.OrdinalIgnoreCase) ||
               string.Equals(modelType, DomainAssociationModelType, StringComparison.OrdinalIgnoreCase) ||
               IsPageLikeModelType(modelType);
    }

    private static string? BuildResourceSpecificDetails(
        string changeType,
        ResourceDescriptor? workingDescriptor,
        ResourceDescriptor? headDescriptor,
        DumpSnapshot workingSnapshot,
        DumpSnapshot headSnapshot)
    {
        var reference = workingDescriptor ?? headDescriptor;
        if (reference is null)
        {
            return null;
        }

        string? details = null;
        if (IsFlowModelType(reference.ModelType))
        {
            details = BuildMicroflowActionDetails(
                changeType,
                reference.ModelType,
                workingDescriptor?.Object,
                headDescriptor?.Object);

            if (string.IsNullOrWhiteSpace(details) &&
                string.Equals(changeType, "Modified", StringComparison.OrdinalIgnoreCase))
            {
                // Keep modified flow output focused on deterministic property deltas
                // (for example allowedModuleRoles count x->y) without generic inventory noise.
                return null;
            }

            return string.IsNullOrWhiteSpace(details)
                ? BuildGenericResourceDetails(changeType, reference.ModelType, workingDescriptor?.Object, headDescriptor?.Object)
                : details;
        }

        if (string.Equals(reference.ModelType, DomainEntityModelType, StringComparison.OrdinalIgnoreCase))
        {
            return BuildDomainEntityAttributeDetails(changeType, workingDescriptor?.Object, headDescriptor?.Object);
        }

        if (string.Equals(reference.ModelType, DomainAssociationModelType, StringComparison.OrdinalIgnoreCase))
        {
            details = BuildDomainAssociationDetails(
                workingDescriptor?.Object,
                headDescriptor?.Object,
                workingSnapshot,
                headSnapshot);
            return string.IsNullOrWhiteSpace(details)
                ? BuildGenericResourceDetails(changeType, reference.ModelType, workingDescriptor?.Object, headDescriptor?.Object)
                : details;
        }

        if (IsEnumerationModelType(reference.ModelType))
        {
            details = BuildEnumerationValueDetails(changeType, workingDescriptor?.Object, headDescriptor?.Object);
            return string.IsNullOrWhiteSpace(details)
                ? BuildGenericResourceDetails(changeType, reference.ModelType, workingDescriptor?.Object, headDescriptor?.Object)
                : details;
        }

        if (IsPageLikeModelType(reference.ModelType))
        {
            details = string.Equals(reference.ModelType, PageModelType, StringComparison.OrdinalIgnoreCase)
                ? BuildPageAllowedRolesDetails(workingDescriptor?.Object, headDescriptor?.Object, workingSnapshot, headSnapshot)
                : null;
            details = MergeDetailTexts(details, BuildPageLayoutMetadataDetails(workingDescriptor?.Object, headDescriptor?.Object));
            details = MergeDetailTexts(details, BuildPageActionBindingsDetails(workingDescriptor?.Object, headDescriptor?.Object));
            details = MergeDetailTexts(details, BuildPageWidgetSummaryDetails(workingDescriptor?.Object, headDescriptor?.Object));
            return string.IsNullOrWhiteSpace(details)
                ? BuildGenericResourceDetails(changeType, reference.ModelType, workingDescriptor?.Object, headDescriptor?.Object)
                : details;
        }

        if (string.Equals(reference.ModelType, ConstantModelType, StringComparison.OrdinalIgnoreCase))
        {
            details = BuildConstantDetails(changeType, workingDescriptor?.Object, headDescriptor?.Object);
            return string.IsNullOrWhiteSpace(details)
                ? BuildGenericResourceDetails(changeType, reference.ModelType, workingDescriptor?.Object, headDescriptor?.Object)
                : details;
        }

        if (string.Equals(reference.ModelType, ScheduledEventModelType, StringComparison.OrdinalIgnoreCase))
        {
            details = BuildScheduledEventDetails(changeType, workingDescriptor?.Object, headDescriptor?.Object);
            return string.IsNullOrWhiteSpace(details)
                ? BuildGenericResourceDetails(changeType, reference.ModelType, workingDescriptor?.Object, headDescriptor?.Object)
                : details;
        }

        if (string.Equals(reference.ModelType, ConsumedRestServiceModelType, StringComparison.OrdinalIgnoreCase))
        {
            details = BuildConsumedRestServiceDetails(changeType, workingDescriptor?.Object, headDescriptor?.Object);
            return string.IsNullOrWhiteSpace(details)
                ? BuildGenericResourceDetails(changeType, reference.ModelType, workingDescriptor?.Object, headDescriptor?.Object)
                : details;
        }

        if (string.Equals(reference.ModelType, PublishedRestServiceModelType, StringComparison.OrdinalIgnoreCase))
        {
            details = BuildPublishedRestServiceDetails(changeType, workingDescriptor?.Object, headDescriptor?.Object);
            return string.IsNullOrWhiteSpace(details)
                ? BuildGenericResourceDetails(changeType, reference.ModelType, workingDescriptor?.Object, headDescriptor?.Object)
                : details;
        }

        if (string.Equals(reference.ModelType, JavaActionModelType, StringComparison.OrdinalIgnoreCase))
        {
            details = BuildJavaActionDetails(changeType, workingDescriptor?.Object, headDescriptor?.Object);
            return string.IsNullOrWhiteSpace(details)
                ? BuildGenericResourceDetails(changeType, reference.ModelType, workingDescriptor?.Object, headDescriptor?.Object)
                : details;
        }

        details = BuildGenericResourceDetails(changeType, reference.ModelType, workingDescriptor?.Object, headDescriptor?.Object);
        if (!string.IsNullOrWhiteSpace(details))
        {
            return details;
        }

        return null;
    }

    private static string? BuildMicroflowActionDetails(
        string changeType,
        string modelType,
        JsonElement? workingResource,
        JsonElement? headResource)
    {
        var details = BuildMicroflowActionDeltaDetails(workingResource, headResource);
        if (!string.IsNullOrWhiteSpace(details))
        {
            return details;
        }

        return BuildFlowMetadataDetails(changeType, modelType, workingResource, headResource);
    }

    private static string? BuildMicroflowActionDeltaDetails(
        JsonElement? workingResource,
        JsonElement? headResource)
    {
        var workingActions = workingResource is null
            ? new Dictionary<string, MicroflowActionInfo>(StringComparer.OrdinalIgnoreCase)
            : CollectMicroflowActionsById(workingResource.Value);
        var headActions = headResource is null
            ? new Dictionary<string, MicroflowActionInfo>(StringComparer.OrdinalIgnoreCase)
            : CollectMicroflowActionsById(headResource.Value);
        var workingLoops = workingResource is null
            ? new Dictionary<string, FlowLoopInfo>(StringComparer.OrdinalIgnoreCase)
            : CollectFlowLoopsById(workingResource.Value);
        var headLoops = headResource is null
            ? new Dictionary<string, FlowLoopInfo>(StringComparer.OrdinalIgnoreCase)
            : CollectFlowLoopsById(headResource.Value);
        var workingDecisions = workingResource is null
            ? new Dictionary<string, FlowDecisionInfo>(StringComparer.OrdinalIgnoreCase)
            : CollectFlowDecisionsById(workingResource.Value);
        var headDecisions = headResource is null
            ? new Dictionary<string, FlowDecisionInfo>(StringComparer.OrdinalIgnoreCase)
            : CollectFlowDecisionsById(headResource.Value);
        var workingAnnotations = workingResource is null
            ? new Dictionary<string, FlowAnnotationInfo>(StringComparer.OrdinalIgnoreCase)
            : CollectFlowAnnotationsById(workingResource.Value);
        var headAnnotations = headResource is null
            ? new Dictionary<string, FlowAnnotationInfo>(StringComparer.OrdinalIgnoreCase)
            : CollectFlowAnnotationsById(headResource.Value);

        var added = new List<MicroflowActionInfo>();
        var removed = new List<MicroflowActionInfo>();
        var modified = new List<(MicroflowActionInfo Head, MicroflowActionInfo Working)>();
        var addedLoops = new List<FlowLoopInfo>();
        var removedLoops = new List<FlowLoopInfo>();
        var modifiedLoops = new List<(FlowLoopInfo Head, FlowLoopInfo Working)>();
        var addedDecisions = new List<FlowDecisionInfo>();
        var removedDecisions = new List<FlowDecisionInfo>();
        var modifiedDecisions = new List<(FlowDecisionInfo Head, FlowDecisionInfo Working)>();
        var addedAnnotations = new List<FlowAnnotationInfo>();
        var removedAnnotations = new List<FlowAnnotationInfo>();
        var modifiedAnnotations = new List<(FlowAnnotationInfo Head, FlowAnnotationInfo Working)>();

        foreach (var (actionId, workingAction) in workingActions)
        {
            if (!headActions.TryGetValue(actionId, out var headAction))
            {
                added.Add(workingAction);
                continue;
            }

            if (!ElementsSemanticallyEqual(workingAction.ActionElement, headAction.ActionElement))
            {
                modified.Add((headAction, workingAction));
            }
        }

        foreach (var (actionId, headAction) in headActions)
        {
            if (!workingActions.ContainsKey(actionId))
            {
                removed.Add(headAction);
            }
        }

        foreach (var (loopId, workingLoop) in workingLoops)
        {
            if (!headLoops.TryGetValue(loopId, out var headLoop))
            {
                addedLoops.Add(workingLoop);
                continue;
            }

            if (!ElementsSemanticallyEqual(workingLoop.LoopElement, headLoop.LoopElement))
            {
                modifiedLoops.Add((headLoop, workingLoop));
            }
        }

        foreach (var (loopId, headLoop) in headLoops)
        {
            if (!workingLoops.ContainsKey(loopId))
            {
                removedLoops.Add(headLoop);
            }
        }

        foreach (var (decisionId, workingDecision) in workingDecisions)
        {
            if (!headDecisions.TryGetValue(decisionId, out var headDecision))
            {
                addedDecisions.Add(workingDecision);
                continue;
            }

            if (!ElementsSemanticallyEqual(workingDecision.DecisionElement, headDecision.DecisionElement))
            {
                modifiedDecisions.Add((headDecision, workingDecision));
            }
        }

        foreach (var (decisionId, headDecision) in headDecisions)
        {
            if (!workingDecisions.ContainsKey(decisionId))
            {
                removedDecisions.Add(headDecision);
            }
        }

        foreach (var (annotationId, workingAnnotation) in workingAnnotations)
        {
            if (!headAnnotations.TryGetValue(annotationId, out var headAnnotation))
            {
                addedAnnotations.Add(workingAnnotation);
                continue;
            }

            if (!ElementsSemanticallyEqual(workingAnnotation.AnnotationElement, headAnnotation.AnnotationElement))
            {
                modifiedAnnotations.Add((headAnnotation, workingAnnotation));
            }
        }

        foreach (var (annotationId, headAnnotation) in headAnnotations)
        {
            if (!workingAnnotations.ContainsKey(annotationId))
            {
                removedAnnotations.Add(headAnnotation);
            }
        }

        if (added.Count == 0 && removed.Count == 0 && modified.Count == 0 &&
            addedLoops.Count == 0 && removedLoops.Count == 0 && modifiedLoops.Count == 0 &&
            addedDecisions.Count == 0 && removedDecisions.Count == 0 && modifiedDecisions.Count == 0 &&
            addedAnnotations.Count == 0 && removedAnnotations.Count == 0 && modifiedAnnotations.Count == 0)
        {
            return null;
        }

        var parts = new List<string>();
        if (added.Count > 0 || removed.Count > 0 || modified.Count > 0)
        {
            parts.Add($"actions delta: added {added.Count}, removed {removed.Count}, modified {modified.Count}");
        }

        if (added.Count > 0)
        {
            parts.Add($"actions added ({added.Count}): {FormatActionTypeCounts(added)}");
        }

        if (removed.Count > 0)
        {
            parts.Add($"actions removed ({removed.Count}): {FormatActionTypeCounts(removed)}");
        }

        if (modified.Count > 0)
        {
            parts.Add($"actions modified ({modified.Count}): {FormatActionTypeCounts(modified.Select(entry => entry.Working))}");
        }

        if (added.Count > 0)
        {
            parts.Add($"added action details: {FormatActionInstanceDetails(added)}");
        }

        if (removed.Count > 0)
        {
            parts.Add($"removed action details: {FormatActionInstanceDetails(removed)}");
        }

        if (modified.Count > 0)
        {
            parts.Add($"modified action details: {FormatModifiedActionDetails(modified)}");
        }

        if (addedLoops.Count > 0 || removedLoops.Count > 0 || modifiedLoops.Count > 0)
        {
            parts.Add($"loops delta: added {addedLoops.Count}, removed {removedLoops.Count}, modified {modifiedLoops.Count}");
        }

        if (addedLoops.Count > 0)
        {
            parts.Add($"loops added ({addedLoops.Count}): {FormatLoopInstanceDetails(addedLoops)}");
        }

        if (removedLoops.Count > 0)
        {
            parts.Add($"loops removed ({removedLoops.Count}): {FormatLoopInstanceDetails(removedLoops)}");
        }

        if (modifiedLoops.Count > 0)
        {
            parts.Add($"loops modified ({modifiedLoops.Count}): {FormatModifiedLoopDetails(modifiedLoops)}");
        }

        if (addedDecisions.Count > 0 || removedDecisions.Count > 0 || modifiedDecisions.Count > 0)
        {
            parts.Add($"decisions delta: added {addedDecisions.Count}, removed {removedDecisions.Count}, modified {modifiedDecisions.Count}");
        }

        if (addedDecisions.Count > 0)
        {
            parts.Add($"decisions added ({addedDecisions.Count}): {FormatDecisionInstanceDetails(addedDecisions)}");
        }

        if (removedDecisions.Count > 0)
        {
            parts.Add($"decisions removed ({removedDecisions.Count}): {FormatDecisionInstanceDetails(removedDecisions)}");
        }

        if (modifiedDecisions.Count > 0)
        {
            parts.Add($"decisions modified ({modifiedDecisions.Count}): {FormatModifiedDecisionDetails(modifiedDecisions)}");
        }

        if (addedAnnotations.Count > 0 || removedAnnotations.Count > 0 || modifiedAnnotations.Count > 0)
        {
            parts.Add($"annotations delta: added {addedAnnotations.Count}, removed {removedAnnotations.Count}, modified {modifiedAnnotations.Count}");
        }

        if (addedAnnotations.Count > 0)
        {
            parts.Add($"annotations added ({addedAnnotations.Count}): {FormatAnnotationInstanceDetails(addedAnnotations)}");
        }

        if (removedAnnotations.Count > 0)
        {
            parts.Add($"annotations removed ({removedAnnotations.Count}): {FormatAnnotationInstanceDetails(removedAnnotations)}");
        }

        if (modifiedAnnotations.Count > 0)
        {
            parts.Add($"annotations modified ({modifiedAnnotations.Count}): {FormatModifiedAnnotationDetails(modifiedAnnotations)}");
        }

        return string.Join("; ", parts);
    }

    private static string? BuildFlowMetadataDetails(
        string changeType,
        string modelType,
        JsonElement? workingResource,
        JsonElement? headResource)
    {
        if (string.Equals(changeType, "Modified", StringComparison.OrdinalIgnoreCase))
        {
            // For modified flows, preserve explicit delta signals from generic diff
            // and avoid re-introducing baseline structure/metadata noise.
            return null;
        }

        var flowResource = workingResource ?? headResource;
        if (flowResource is null)
        {
            return null;
        }

        var flowObject = flowResource.Value;
        var actionCount = CollectMicroflowActionsById(flowObject).Count;
        var loopCount = CollectFlowLoopsById(flowObject).Count;
        var decisionCount = CollectFlowDecisionsById(flowObject).Count;
        var sequenceFlowCount = TryGetArrayPropertyCount(flowObject, "flows") ?? 0;
        var allowedRolesCount = TryGetArrayPropertyCount(flowObject, "allowedModuleRoles") ?? 0;

        var parts = new List<string>();
        if (actionCount == 0 && loopCount == 0 && decisionCount == 0)
        {
            parts.Add($"flow structure: no action/loop/decision activities configured; sequenceFlows={sequenceFlowCount}");
        }
        else
        {
            parts.Add($"flow structure: actions={actionCount}, loops={loopCount}, decisions={decisionCount}, sequenceFlows={sequenceFlowCount}");
        }

        var metadata = new List<string>();
        AppendOption(metadata, "modelType", ShortTypeName(modelType));
        AppendOption(metadata, "applyEntityAccess", TryReadStringProperty(flowObject, "applyEntityAccess"));
        AppendOption(metadata, "allowConcurrentExecution", TryReadStringProperty(flowObject, "allowConcurrentExecution"));
        AppendOption(metadata, "markAsUsed", TryReadStringProperty(flowObject, "markAsUsed"));
        AppendOption(metadata, "returnVariableName", TryReadStringProperty(flowObject, "returnVariableName"));
        AppendOption(metadata, "url", TryReadStringProperty(flowObject, "url"), maxLength: 160);
        if (allowedRolesCount > 0)
        {
            metadata.Add($"allowedModuleRoles={allowedRolesCount}");
        }

        if (metadata.Count > 0)
        {
            parts.Add($"flow metadata: {string.Join(", ", metadata)}");
        }

        if (string.Equals(changeType, "Added", StringComparison.OrdinalIgnoreCase) && parts.Count == 0)
        {
            parts.Add("flow created");
        }
        else if (string.Equals(changeType, "Deleted", StringComparison.OrdinalIgnoreCase) && parts.Count == 0)
        {
            parts.Add("flow before deletion");
        }

        return parts.Count == 0 ? null : string.Join("; ", parts);
    }

    private static Dictionary<string, FlowLoopInfo> CollectFlowLoopsById(JsonElement flowObject)
    {
        var loopsById = new Dictionary<string, FlowLoopInfo>(StringComparer.OrdinalIgnoreCase);
        var duplicateCounters = new Dictionary<string, int>(StringComparer.OrdinalIgnoreCase);
        var stack = new Stack<JsonElement>();
        stack.Push(flowObject);

        while (stack.Count > 0)
        {
            var current = stack.Pop();
            switch (current.ValueKind)
            {
                case JsonValueKind.Object:
                {
                    var modelType = TryReadStringProperty(current, "$Type");
                    if (string.Equals(modelType, LoopedActivityModelType, StringComparison.OrdinalIgnoreCase))
                    {
                        var descriptor = BuildLoopDescriptor(current) ?? "loop payload changed";
                        var loopId = TryReadStringProperty(current, "$ID") ?? BuildFallbackLoopId(descriptor);

                        if (loopsById.ContainsKey(loopId))
                        {
                            duplicateCounters.TryGetValue(loopId, out var duplicateIndex);
                            duplicateIndex++;
                            duplicateCounters[loopId] = duplicateIndex;
                            loopId = $"{loopId}#{duplicateIndex}";
                        }
                        else
                        {
                            duplicateCounters[loopId] = 0;
                        }

                        loopsById[loopId] = new FlowLoopInfo(
                            loopId,
                            NormalizeInlineText(descriptor, maxLength: 180),
                            current);
                    }

                    foreach (var property in current.EnumerateObject())
                    {
                        stack.Push(property.Value);
                    }

                    break;
                }

                case JsonValueKind.Array:
                    foreach (var item in current.EnumerateArray())
                    {
                        stack.Push(item);
                    }

                    break;
            }
        }

        return loopsById;
    }

    private static string BuildFallbackLoopId(string descriptor)
    {
        var normalizedDescriptor = string.IsNullOrWhiteSpace(descriptor)
            ? "loop"
            : NormalizeInlineText(descriptor, maxLength: 90);
        return $"loop:{normalizedDescriptor}";
    }

    private static string? BuildLoopDescriptor(JsonElement loopElement)
    {
        if (!TryReadProperty(loopElement, "loopSource", out var loopSource) ||
            loopSource.ValueKind != JsonValueKind.Object)
        {
            return "iterate";
        }

        var sourceType = ShortTypeName(TryReadStringProperty(loopSource, "$Type") ?? string.Empty);
        var listVariableName = TryReadStringProperty(loopSource, "listVariableName");
        var iteratorVariableName = TryReadStringProperty(loopSource, "variableName");

        var iteratorDescriptor = string.Empty;
        if (!string.IsNullOrWhiteSpace(listVariableName) && !string.IsNullOrWhiteSpace(iteratorVariableName))
        {
            iteratorDescriptor = $"iterate {listVariableName} as {iteratorVariableName}";
        }
        else if (!string.IsNullOrWhiteSpace(listVariableName))
        {
            iteratorDescriptor = $"iterate {listVariableName}";
        }
        else if (!string.IsNullOrWhiteSpace(iteratorVariableName))
        {
            iteratorDescriptor = $"iterate as {iteratorVariableName}";
        }
        else
        {
            iteratorDescriptor = "iterate";
        }

        var details = new List<string>();
        if (!string.IsNullOrWhiteSpace(sourceType) && !string.Equals(sourceType, "<unknown>", StringComparison.OrdinalIgnoreCase))
        {
            details.Add($"source={sourceType}");
        }

        if (details.Count == 0)
        {
            return iteratorDescriptor;
        }

        return $"{iteratorDescriptor} ({string.Join(", ", details)})";
    }

    private static string FormatLoopInstanceDetails(
        IEnumerable<FlowLoopInfo> loops,
        int maxEntries = 5)
    {
        var details = loops
            .Select(loop => loop.DescriptorText)
            .Distinct(StringComparer.OrdinalIgnoreCase)
            .OrderBy(detail => detail, StringComparer.OrdinalIgnoreCase)
            .ToArray();

        if (details.Length == 0)
        {
            return "<none>";
        }

        var visible = details.Take(maxEntries).ToList();
        var remaining = details.Length - visible.Count;
        if (remaining > 0)
        {
            visible.Add($"+{remaining} more");
        }

        return string.Join(" | ", visible);
    }

