    private static string? BuildDecisionDescriptor(JsonElement decisionElement)
    {
        var caption = TryReadStringProperty(decisionElement, "caption");
        var expression = string.Empty;

        if (TryReadProperty(decisionElement, "splitCondition", out var splitCondition) &&
            splitCondition.ValueKind == JsonValueKind.Object)
        {
            expression = TryReadStringProperty(splitCondition, "expression") ?? string.Empty;
        }

        var parts = new List<string>();
        if (!string.IsNullOrWhiteSpace(caption))
        {
            parts.Add(NormalizeInlineText(caption, maxLength: 120));
        }

        if (!string.IsNullOrWhiteSpace(expression))
        {
            parts.Add($"expression={NormalizeInlineText(expression, maxLength: 120)}");
        }

        if (parts.Count == 0)
        {
            return "decision";
        }

        return string.Join(" ", parts);
    }

