    private static string ResolveAssociationCardinality(
        string? associationType,
        string? associationOwner,
        bool fromParentPerspective)
    {
        if (string.Equals(associationType, "ReferenceSet", StringComparison.OrdinalIgnoreCase))
        {
            return "*-*";
        }

        if (string.Equals(associationType, "Reference", StringComparison.OrdinalIgnoreCase))
        {
            if (string.Equals(associationOwner, "Both", StringComparison.OrdinalIgnoreCase))
            {
                return "1-1";
            }

            if (string.Equals(associationOwner, "Parent", StringComparison.OrdinalIgnoreCase))
            {
                return fromParentPerspective ? "1-*" : "*-1";
            }

            if (string.Equals(associationOwner, "Child", StringComparison.OrdinalIgnoreCase))
            {
                return fromParentPerspective ? "*-1" : "1-*";
            }

            return fromParentPerspective ? "*-1" : "1-*";
        }

        return "1-1";
    }

    private static string? BuildEntityRenameDetails(
        string changeType,
        JsonElement? workingResource,
        JsonElement? headResource)
    {
        if (!string.Equals(changeType, "Modified", StringComparison.OrdinalIgnoreCase))
        {
            return null;
        }

        if (workingResource is null || headResource is null)
        {
            return null;
        }

        var currentName = TryReadStringProperty(workingResource.Value, "name");
        var previousName = TryReadStringProperty(headResource.Value, "name");
        if (string.IsNullOrWhiteSpace(currentName) ||
            string.IsNullOrWhiteSpace(previousName) ||
            string.Equals(currentName, previousName, StringComparison.OrdinalIgnoreCase))
        {
            return null;
        }

        return $"renamed from {NormalizeInlineText(previousName, 120)}";
    }

    private static string? BuildEntityGeneralizationDetails(
        string changeType,
        JsonElement? workingResource,
        JsonElement? headResource)
    {
        var currentGeneralization = workingResource is null
            ? null
            : ResolveEntityGeneralizationTarget(workingResource.Value);
        var previousGeneralization = headResource is null
            ? null
            : ResolveEntityGeneralizationTarget(headResource.Value);

        if (string.Equals(changeType, "Added", StringComparison.OrdinalIgnoreCase))
        {
            if (string.IsNullOrWhiteSpace(currentGeneralization))
            {
                return null;
            }

            return $"Generalization of {FormatGeneralizationTarget(currentGeneralization)}";
        }

        if (string.Equals(changeType, "Deleted", StringComparison.OrdinalIgnoreCase))
        {
            if (string.IsNullOrWhiteSpace(previousGeneralization))
            {
                return null;
            }

            return $"Generalization of {FormatGeneralizationTarget(previousGeneralization)}";
        }

        if (string.Equals(currentGeneralization, previousGeneralization, StringComparison.OrdinalIgnoreCase))
        {
            return null;
        }

        if (string.IsNullOrWhiteSpace(previousGeneralization))
        {
            return $"Generalization of {FormatGeneralizationTarget(currentGeneralization)}";
        }

        if (string.IsNullOrWhiteSpace(currentGeneralization))
        {
            return $"Generalization of {FormatGeneralizationTarget(previousGeneralization)}-><none>";
        }

        return $"Generalization of {FormatGeneralizationTarget(previousGeneralization)}->{FormatGeneralizationTarget(currentGeneralization)}";
    }

    private static string? ResolveEntityGeneralizationTarget(JsonElement entityResource)
    {
        if (!TryReadProperty(entityResource, "generalization", out var generalizationElement) ||
            generalizationElement.ValueKind != JsonValueKind.Object)
        {
            return null;
        }

        var generalizationType = TryReadStringProperty(generalizationElement, "$Type");
        if (string.Equals(generalizationType, "DomainModels$NoGeneralization", StringComparison.OrdinalIgnoreCase))
        {
            return null;
        }

        return TryReadStringProperty(generalizationElement, "generalization");
    }

    private static string FormatGeneralizationTarget(string? target)
    {
        if (string.IsNullOrWhiteSpace(target))
        {
            return "<none>";
        }

        return NormalizeInlineText(target, 120);
    }

    private static string? BuildEntitySystemMemberDetails(
        JsonElement? workingResource,
        JsonElement? headResource)
    {
        var currentFlags = workingResource is null
            ? new Dictionary<string, bool>(StringComparer.OrdinalIgnoreCase)
            : CollectEntitySystemMemberFlags(workingResource.Value);
        var previousFlags = headResource is null
            ? new Dictionary<string, bool>(StringComparer.OrdinalIgnoreCase)
            : CollectEntitySystemMemberFlags(headResource.Value);

        var enabledFlags = new List<string>();
        var disabledFlags = new List<string>();
        foreach (var (propertyName, label) in EntitySystemMemberFlags)
        {
            var currentValue = currentFlags.TryGetValue(propertyName, out var currentFlagValue) && currentFlagValue;
            var previousValue = previousFlags.TryGetValue(propertyName, out var previousFlagValue) && previousFlagValue;
            if (currentValue == previousValue)
            {
                continue;
            }

            if (currentValue)
            {
                enabledFlags.Add(label);
            }
            else
            {
                disabledFlags.Add(label);
            }
        }

        if (enabledFlags.Count == 0 && disabledFlags.Count == 0)
        {
            return null;
        }

        var details = new List<string>();
        if (enabledFlags.Count > 0)
        {
            details.Add($"enabled {string.Join(", ", enabledFlags)}");
        }

        if (disabledFlags.Count > 0)
        {
            details.Add($"disabled {string.Join(", ", disabledFlags)}");
        }

        return $"system members: {string.Join("; ", details)}";
    }

    private static Dictionary<string, bool> CollectEntitySystemMemberFlags(JsonElement entityResource)
    {
        var flags = new Dictionary<string, bool>(StringComparer.OrdinalIgnoreCase);
        if (!TryReadProperty(entityResource, "generalization", out var generalizationElement) ||
            generalizationElement.ValueKind != JsonValueKind.Object)
        {
            return flags;
        }

        foreach (var (propertyName, _) in EntitySystemMemberFlags)
        {
            if (TryReadBooleanProperty(generalizationElement, propertyName, out var value))
            {
                flags[propertyName] = value;
            }
        }

        return flags;
    }

    private static string? BuildEntityCommitHandlerDetails(
        JsonElement? workingResource,
        JsonElement? headResource)
    {
        var previousBeforeHandlers = headResource is null
            ? Array.Empty<string>()
            : CollectEntityCommitHandlerTargets(headResource.Value, "Before");
        var currentBeforeHandlers = workingResource is null
            ? Array.Empty<string>()
            : CollectEntityCommitHandlerTargets(workingResource.Value, "Before");
        var previousAfterHandlers = headResource is null
            ? Array.Empty<string>()
            : CollectEntityCommitHandlerTargets(headResource.Value, "After");
        var currentAfterHandlers = workingResource is null
            ? Array.Empty<string>()
            : CollectEntityCommitHandlerTargets(workingResource.Value, "After");

        var details = new List<string>();
        var beforeDetails = BuildEntityCommitHandlerMomentDetails(
            "before commit",
            previousBeforeHandlers,
            currentBeforeHandlers);
        if (!string.IsNullOrWhiteSpace(beforeDetails))
        {
            details.Add(beforeDetails);
        }

        var afterDetails = BuildEntityCommitHandlerMomentDetails(
            "after commit",
            previousAfterHandlers,
            currentAfterHandlers);
        if (!string.IsNullOrWhiteSpace(afterDetails))
        {
            details.Add(afterDetails);
        }

        return details.Count == 0
            ? null
            : string.Join("; ", details);
    }

    private static string[] CollectEntityCommitHandlerTargets(JsonElement entityResource, string moment)
    {
        if (!TryReadProperty(entityResource, "eventHandlers", out var eventHandlersElement) ||
            eventHandlersElement.ValueKind != JsonValueKind.Array)
        {
            return Array.Empty<string>();
        }

        var targets = new HashSet<string>(StringComparer.OrdinalIgnoreCase);
        foreach (var eventHandler in eventHandlersElement.EnumerateArray())
        {
            if (eventHandler.ValueKind != JsonValueKind.Object)
            {
                continue;
            }

            var eventName = TryReadStringProperty(eventHandler, "event");
            if (!string.Equals(eventName, "Commit", StringComparison.OrdinalIgnoreCase))
            {
                continue;
            }

            var eventMoment = TryReadStringProperty(eventHandler, "moment");
            if (!string.Equals(eventMoment, moment, StringComparison.OrdinalIgnoreCase))
            {
                continue;
            }

            var microflowName = TryReadStringProperty(eventHandler, "microflow");
            if (string.IsNullOrWhiteSpace(microflowName))
            {
                continue;
            }

            targets.Add(ShortName(microflowName));
        }

        return targets
            .OrderBy(target => target, StringComparer.OrdinalIgnoreCase)
            .ToArray();
    }

    private static string? BuildEntityCommitHandlerMomentDetails(
        string label,
        IReadOnlyCollection<string> previousTargets,
        IReadOnlyCollection<string> currentTargets)
    {
        var sameTargets = previousTargets.Count == currentTargets.Count &&
                          previousTargets.All(target => currentTargets.Contains(target, StringComparer.OrdinalIgnoreCase));
        if (sameTargets)
        {
            return null;
        }

        if (previousTargets.Count == 0 && currentTargets.Count > 0)
        {
            return $"{label}={string.Join(", ", currentTargets)}";
        }

        if (previousTargets.Count > 0 && currentTargets.Count == 0)
        {
            return $"{label} removed";
        }

        return $"{label} {string.Join(", ", previousTargets)}->{string.Join(", ", currentTargets)}";
    }

    private static string? ResolveAssociationEntityName(
        JsonElement associationResource,
        string endPropertyName,
        DumpSnapshot workingSnapshot,
        DumpSnapshot headSnapshot)
    {
        var entityId = TryReadStringProperty(associationResource, endPropertyName);
        if (string.IsNullOrWhiteSpace(entityId))
        {
            return null;
        }

        if (TryResolveDomainEntityName(workingSnapshot, entityId, out var workingName))
        {
            return workingName;
        }

        if (TryResolveDomainEntityName(headSnapshot, entityId, out var headName))
        {
            return headName;
        }

        return entityId;
    }

    private static bool TryResolveDomainEntityName(
        DumpSnapshot snapshot,
        string entityId,
        out string? entityName)
    {
        entityName = null;
        if (!snapshot.ObjectsById.TryGetValue(entityId, out var entityObject))
        {
            return false;
        }

        var modelType = TryReadStringProperty(entityObject, "$Type");
        if (!string.Equals(modelType, DomainEntityModelType, StringComparison.OrdinalIgnoreCase))
        {
            return false;
        }

        entityName = ResolveElementName(entityObject);
        return !string.IsNullOrWhiteSpace(entityName);
    }

    private static string? BuildEnumerationValueDetails(
        string changeType,
        JsonElement? workingResource,
        JsonElement? headResource)
    {
        var workingValues = workingResource is null
            ? new Dictionary<string, EnumerationValueInfo>(StringComparer.OrdinalIgnoreCase)
            : CollectEnumerationValues(workingResource.Value);
        var headValues = headResource is null
            ? new Dictionary<string, EnumerationValueInfo>(StringComparer.OrdinalIgnoreCase)
            : CollectEnumerationValues(headResource.Value);

        if (string.Equals(changeType, "Added", StringComparison.OrdinalIgnoreCase))
        {
            if (workingValues.Count == 0)
            {
                return null;
            }

            var details = $"values added ({workingValues.Count}): {FormatNameList(workingValues.Values.Select(value => value.Name))}";
            return MergeDetailTexts(details, BuildEnumerationCaptionMismatchDetails(workingValues.Values));
        }

        if (string.Equals(changeType, "Deleted", StringComparison.OrdinalIgnoreCase))
        {
            if (headValues.Count == 0)
            {
                return null;
            }

            return $"values before deletion ({headValues.Count}): {FormatNameList(headValues.Values.Select(value => value.Name))}";
        }

        var addedKeys = workingValues.Keys
            .Except(headValues.Keys, StringComparer.OrdinalIgnoreCase)
            .ToArray();
        var removedKeys = headValues.Keys
            .Except(workingValues.Keys, StringComparer.OrdinalIgnoreCase)
            .ToArray();
        var modifiedKeys = workingValues.Keys
            .Intersect(headValues.Keys, StringComparer.OrdinalIgnoreCase)
            .Where(key => !ElementsSemanticallyEqual(workingValues[key].ValueElement, headValues[key].ValueElement))
            .ToArray();

        if (addedKeys.Length == 0 && removedKeys.Length == 0 && modifiedKeys.Length == 0)
        {
            return null;
        }

        var parts = new List<string>
        {
            $"values delta: added {addedKeys.Length}, removed {removedKeys.Length}, modified {modifiedKeys.Length}",
        };

        if (addedKeys.Length > 0)
        {
            parts.Add($"values added ({addedKeys.Length}): {FormatNameList(addedKeys.Select(key => workingValues[key].Name))}");
        }

        if (removedKeys.Length > 0)
        {
            parts.Add($"values removed ({removedKeys.Length}): {FormatNameList(removedKeys.Select(key => headValues[key].Name))}");
        }

        if (modifiedKeys.Length > 0)
        {
            parts.Add($"values modified ({modifiedKeys.Length}): {FormatNameList(modifiedKeys.Select(key => workingValues[key].Name))}");
        }

        var mismatchCandidates = addedKeys
            .Concat(modifiedKeys)
            .Select(key => workingValues[key]);
        var captionMismatchDetails = BuildEnumerationCaptionMismatchDetails(mismatchCandidates);
        if (!string.IsNullOrWhiteSpace(captionMismatchDetails))
        {
            parts.Add(captionMismatchDetails);
        }

        return string.Join("; ", parts);
    }

    private static Dictionary<string, EnumerationValueInfo> CollectEnumerationValues(JsonElement enumerationObject)
    {
        var valuesById = new Dictionary<string, EnumerationValueInfo>(StringComparer.OrdinalIgnoreCase);
        if (!TryReadProperty(enumerationObject, "values", out var valuesElement) ||
            valuesElement.ValueKind != JsonValueKind.Array)
        {
            return valuesById;
        }

        var index = 0;
        foreach (var valueElement in valuesElement.EnumerateArray())
        {
            if (valueElement.ValueKind != JsonValueKind.Object)
            {
                index++;
                continue;
            }

            var valueId =
                TryReadAnyStringProperty(valueElement, "$ID", "name", "$QualifiedName") ??
                $"index-{index}";
            var valueName =
                TryReadAnyStringProperty(valueElement, "name", "$QualifiedName", "$ID") ??
                valueId;
            var caption = TryReadTranslatableTextProperty(valueElement, "caption");

            valuesById[valueId] = new EnumerationValueInfo(
                valueId,
                NormalizeInlineText(valueName, 140),
                string.IsNullOrWhiteSpace(caption) ? null : NormalizeInlineText(caption, 140),
                valueElement);

            index++;
        }

        return valuesById;
    }

    private static string? BuildEnumerationCaptionMismatchDetails(
        IEnumerable<EnumerationValueInfo> values,
        int maxEntries = 5)
    {
        var mismatches = values
            .Where(value =>
                !string.IsNullOrWhiteSpace(value.Name) &&
                !string.IsNullOrWhiteSpace(value.PrimaryCaption) &&
                !string.Equals(value.Name, value.PrimaryCaption, StringComparison.OrdinalIgnoreCase))
            .Select(value => $"{value.Name}(caption={NormalizeInlineText(value.PrimaryCaption!, 90)})")
            .Distinct(StringComparer.OrdinalIgnoreCase)
            .OrderBy(value => value, StringComparer.OrdinalIgnoreCase)
            .ToArray();

        if (mismatches.Length == 0)
        {
            return null;
        }

        var visible = mismatches.Take(maxEntries).ToList();
        var remaining = mismatches.Length - visible.Count;
        if (remaining > 0)
        {
            visible.Add($"+{remaining} more");
        }

        return $"caption mismatch: {string.Join(", ", visible)}";
    }

    private static string? BuildPageLayoutMetadataDetails(
        JsonElement? workingResource,
        JsonElement? headResource)
    {
        if (workingResource is not null && headResource is not null)
        {
            var modifiedDetails = new List<string>();
            AddPageMetadataDelta(
                modifiedDetails,
                "layout",
                TryReadNestedStringProperty(headResource.Value, "layoutCall", "layout"),
                TryReadNestedStringProperty(workingResource.Value, "layoutCall", "layout"),
                maxLength: 120,
                emptyToken: "<empty>");
            AddPageMetadataDelta(
                modifiedDetails,
                "title",
                TryReadTranslatableTextProperty(headResource.Value, "title"),
                TryReadTranslatableTextProperty(workingResource.Value, "title"),
                maxLength: 120,
                emptyToken: "<empty>");
            AddPageMetadataDelta(
                modifiedDetails,
                "url",
                TryReadStringProperty(headResource.Value, "url"),
                TryReadStringProperty(workingResource.Value, "url"),
                maxLength: 180,
                emptyToken: "<empty>");
            AddPageMetadataDelta(
                modifiedDetails,
                "popup",
                BuildPagePopupMetadata(headResource.Value),
                BuildPagePopupMetadata(workingResource.Value),
                maxLength: 80,
                emptyToken: "<empty>");

            return modifiedDetails.Count == 0 ? null : string.Join("; ", modifiedDetails);
        }

        var pageResource = workingResource ?? headResource;
        if (pageResource is null)
        {
            return null;
        }

        var details = new List<string>();
        var layout = TryReadNestedStringProperty(pageResource.Value, "layoutCall", "layout");
        if (!string.IsNullOrWhiteSpace(layout))
        {
            details.Add($"layout={NormalizeInlineText(layout, 120)}");
        }

        var title = TryReadTranslatableTextProperty(pageResource.Value, "title");
        if (!string.IsNullOrWhiteSpace(title))
        {
            details.Add($"title={NormalizeInlineText(title, 120)}");
        }

        var url = TryReadStringProperty(pageResource.Value, "url");
        details.Add(string.IsNullOrWhiteSpace(url)
            ? "url=<empty>"
            : $"url={NormalizeInlineText(url, 180)}");

        var popupWidth = TryReadStringProperty(pageResource.Value, "popupWidth");
        var popupHeight = TryReadStringProperty(pageResource.Value, "popupHeight");
        var popupResizable = TryReadStringProperty(pageResource.Value, "popupResizable");
        if (!string.IsNullOrWhiteSpace(popupWidth) ||
            !string.IsNullOrWhiteSpace(popupHeight) ||
            !string.IsNullOrWhiteSpace(popupResizable))
        {
            var width = string.IsNullOrWhiteSpace(popupWidth) ? "?" : popupWidth;
            var height = string.IsNullOrWhiteSpace(popupHeight) ? "?" : popupHeight;
            var popupDetails = $"popup={width}x{height}";
            if (!string.IsNullOrWhiteSpace(popupResizable))
            {
                popupDetails = $"{popupDetails} resizable={popupResizable}";
            }

            details.Add(popupDetails);
        }

        return details.Count == 0 ? null : string.Join("; ", details);
    }

    private static string? BuildPagePopupMetadata(JsonElement pageResource)
    {
        var popupWidth = TryReadStringProperty(pageResource, "popupWidth");
        var popupHeight = TryReadStringProperty(pageResource, "popupHeight");
        var popupResizable = TryReadStringProperty(pageResource, "popupResizable");
        if (string.IsNullOrWhiteSpace(popupWidth) &&
            string.IsNullOrWhiteSpace(popupHeight) &&
            string.IsNullOrWhiteSpace(popupResizable))
        {
            return null;
        }

        var width = string.IsNullOrWhiteSpace(popupWidth) ? "?" : popupWidth;
        var height = string.IsNullOrWhiteSpace(popupHeight) ? "?" : popupHeight;
        var popupDetails = $"popup={width}x{height}";
        if (!string.IsNullOrWhiteSpace(popupResizable))
        {
            popupDetails = $"{popupDetails} resizable={popupResizable}";
        }

        return popupDetails;
    }

    private static void AddPageMetadataDelta(
        ICollection<string> details,
        string label,
        string? previousValue,
        string? currentValue,
        int maxLength,
        string emptyToken)
    {
        var normalizedPrevious = string.IsNullOrWhiteSpace(previousValue)
            ? string.Empty
            : NormalizeInlineText(previousValue, maxLength);
        var normalizedCurrent = string.IsNullOrWhiteSpace(currentValue)
            ? string.Empty
            : NormalizeInlineText(currentValue, maxLength);
        if (string.Equals(normalizedPrevious, normalizedCurrent, StringComparison.Ordinal))
        {
            return;
        }

        var displayPrevious = normalizedPrevious.Length == 0 ? emptyToken : normalizedPrevious;
        var displayCurrent = normalizedCurrent.Length == 0 ? emptyToken : normalizedCurrent;
        details.Add($"{label} {displayPrevious}->{displayCurrent}");
    }

    private static string? BuildPageActionBindingsDetails(
        JsonElement? workingResource,
        JsonElement? headResource)
    {
        var workingActionBindings = workingResource is null
            ? new List<PageClientActionInfo>()
            : CollectPageClientActions(workingResource.Value);
        var headActionBindings = headResource is null
            ? new List<PageClientActionInfo>()
            : CollectPageClientActions(headResource.Value);

        if (workingResource is not null && headResource is not null)
        {
            var widgetDeltaLines = BuildPageWidgetDeltaLines(workingResource.Value, headResource.Value);
            return widgetDeltaLines.Count == 0
                ? null
                : string.Join("; ", widgetDeltaLines);
        }

        var actionBindings = workingResource is not null
            ? workingActionBindings
            : headActionBindings;
        if (actionBindings.Count == 0)
        {
            return null;
        }

        var counts = new Dictionary<string, int>(StringComparer.OrdinalIgnoreCase);
        foreach (var actionBinding in actionBindings)
        {
            IncrementCount(counts, actionBinding.ActionType);
        }

        var detailsForLifecycleChange = new List<string>
        {
            workingResource is not null
                ? $"actions used ({actionBindings.Count}): {FormatCounterList(counts)}"
                : $"actions before deletion ({actionBindings.Count}): {FormatCounterList(counts)}",
        };

        var targets = CollectDistinctPageActionTargets(actionBindings);
        if (targets.Length > 0)
        {
            detailsForLifecycleChange.Add(workingResource is not null
                ? $"action targets: {FormatNameList(targets, maxEntries: 8)}"
                : $"action targets before deletion: {FormatNameList(targets, maxEntries: 8)}");
        }

        return string.Join("; ", detailsForLifecycleChange);
    }

    private static List<string> BuildPageWidgetDeltaLines(JsonElement workingPageResource, JsonElement headPageResource)
    {
        var workingWidgets = CollectPageWidgetsById(workingPageResource);
        var headWidgets = CollectPageWidgetsById(headPageResource);
        var addedLines = new List<string>();
        var modifiedLines = new List<string>();
        var removedLines = new List<string>();

        foreach (var (widgetId, workingWidget) in workingWidgets)
        {
            if (!headWidgets.TryGetValue(widgetId, out var headWidget))
            {
                addedLines.Add(BuildAddedOrRemovedWidgetLine("added", workingWidget));
                continue;
            }

            if (ElementsSemanticallyEqual(headWidget.WidgetElement, workingWidget.WidgetElement))
            {
                continue;
            }

            modifiedLines.Add(BuildModifiedWidgetLine(headWidget, workingWidget));
        }

        foreach (var (widgetId, headWidget) in headWidgets)
        {
            if (!workingWidgets.ContainsKey(widgetId))
            {
                removedLines.Add(BuildAddedOrRemovedWidgetLine("removed", headWidget));
            }
        }

        var output = new List<string>();
        output.AddRange(addedLines.OrderBy(line => line, StringComparer.OrdinalIgnoreCase));
        output.AddRange(modifiedLines.OrderBy(line => line, StringComparer.OrdinalIgnoreCase));
        output.AddRange(removedLines.OrderBy(line => line, StringComparer.OrdinalIgnoreCase));
        return output;
    }

    private static Dictionary<string, PageWidgetInfo> CollectPageWidgetsById(JsonElement pageResource)
    {
        var widgetMap = new Dictionary<string, PageWidgetInfo>(StringComparer.OrdinalIgnoreCase);
        if (!TryReadProperty(pageResource, "layoutCall", out var layoutCall) ||
            layoutCall.ValueKind != JsonValueKind.Object)
        {
            return widgetMap;
        }

        var stack = new Stack<JsonElement>();
        stack.Push(layoutCall);
        while (stack.Count > 0)
        {
            var current = stack.Pop();
            switch (current.ValueKind)
            {
                case JsonValueKind.Object:
                {
                    var modelType = TryReadStringProperty(current, "$Type");
                    var widgetId = TryReadStringProperty(current, "$ID");
                    if (!string.IsNullOrWhiteSpace(modelType) &&
                        !string.IsNullOrWhiteSpace(widgetId) &&
                        IsPageWidgetModelType(modelType))
                    {
                        widgetMap[widgetId] = new PageWidgetInfo(
                            widgetId,
                            ShortTypeName(modelType),
                            TryReadStringProperty(current, "name"),
                            current);
                    }

                    foreach (var property in current.EnumerateObject())
                    {
                        stack.Push(property.Value);
                    }

                    break;
                }

                case JsonValueKind.Array:
                    foreach (var item in current.EnumerateArray())
                    {
                        stack.Push(item);
                    }

                    break;
            }
        }

        return widgetMap;
    }

    private static string BuildAddedOrRemovedWidgetLine(string changeVerb, PageWidgetInfo widget)
    {
        var widgetLabel = FormatWidgetLabel(widget);
        var bindings = ExtractWidgetBindings(widget.WidgetElement);
        if (bindings.Count == 0)
        {
            return $"{changeVerb} {widgetLabel}";
        }

        var bindingText = string.Join(", ", bindings
            .OrderBy(entry => entry.Key, StringComparer.OrdinalIgnoreCase)
            .Select(entry => $"{entry.Key}={entry.Value}"));
        return $"{changeVerb} {widgetLabel} ({bindingText})";
    }

    private static string BuildModifiedWidgetLine(PageWidgetInfo previousWidget, PageWidgetInfo currentWidget)
    {
        var widgetLabel = FormatWidgetLabel(currentWidget);
        var previousBindings = ExtractWidgetBindings(previousWidget.WidgetElement);
        var currentBindings = ExtractWidgetBindings(currentWidget.WidgetElement);
        var bindingChanges = BuildWidgetBindingChanges(previousBindings, currentBindings);
        if (bindingChanges.Count > 0)
        {
            return $"modified {widgetLabel} ({string.Join(", ", bindingChanges)})";
        }

        var propertySummary = BuildWidgetPropertyChangeSummary(previousWidget.WidgetElement, currentWidget.WidgetElement);
        if (!string.IsNullOrWhiteSpace(propertySummary))
        {
            return $"modified {widgetLabel} ({propertySummary})";
        }

        return $"modified {widgetLabel}";
    }

    private static string FormatWidgetLabel(PageWidgetInfo widget)
    {
        if (!string.IsNullOrWhiteSpace(widget.WidgetName))
        {
            return $"{widget.WidgetType}({NormalizeInlineText(widget.WidgetName, 40)})";
        }

        return widget.WidgetType;
    }

    private static Dictionary<string, string> ExtractWidgetBindings(JsonElement widgetElement)
    {
        var bindings = new Dictionary<string, string>(StringComparer.OrdinalIgnoreCase);

        AddWidgetActionBinding(bindings, widgetElement, "onChangeAction", "onChange");
        AddWidgetActionBinding(bindings, widgetElement, "onClickAction", "onClick");
        AddWidgetActionBinding(bindings, widgetElement, "onEnterAction", "onEnter");
        AddWidgetActionBinding(bindings, widgetElement, "onLeaveAction", "onLeave");
        AddWidgetActionBinding(bindings, widgetElement, "onEnterKeyPressAction", "onEnterKeyPress");
        AddWidgetActionBinding(bindings, widgetElement, "clickAction", "onClick");
        AddWidgetActionBinding(bindings, widgetElement, "pullDownAction", "onPullDown");
        AddWidgetActionBinding(bindings, widgetElement, "action", "action");

        if (TryReadNestedStringProperty(widgetElement, "pageSettings", "page") is { } pageSettingsPage &&
            !string.IsNullOrWhiteSpace(pageSettingsPage))
        {
            bindings["showPage"] = NormalizeInlineText(pageSettingsPage, 140);
        }

        if (TryReadNestedStringProperty(widgetElement, "selectPageSettings", "page") is { } selectPage &&
            !string.IsNullOrWhiteSpace(selectPage))
        {
            bindings["selectPage"] = NormalizeInlineText(selectPage, 140);
        }

        if (TryReadNestedStringProperty(widgetElement, "gotoPageSettings", "page") is { } gotoPage &&
            !string.IsNullOrWhiteSpace(gotoPage))
        {
            bindings["gotoPage"] = NormalizeInlineText(gotoPage, 140);
        }

        if (TryReadProperty(widgetElement, "dataSource", out var dataSourceElement) &&
            TryExtractWidgetSource(dataSourceElement, out var dataSource))
        {
            bindings["source"] = dataSource;
        }

        if (TryReadProperty(widgetElement, "selectorSource", out var selectorSourceElement) &&
            TryExtractWidgetSource(selectorSourceElement, out var selectorSource))
        {
            bindings["source"] = selectorSource;
        }

        return bindings;
    }

    private static void AddWidgetActionBinding(
        Dictionary<string, string> bindings,
        JsonElement widgetElement,
        string propertyName,
        string bindingLabel)
    {
        if (!TryReadProperty(widgetElement, propertyName, out var actionElement) ||
            actionElement.ValueKind != JsonValueKind.Object)
        {
            return;
        }

        if (!TryExtractClientActionTarget(actionElement, out var targetKind, out var targetValue))
        {
            return;
        }

        var effectiveLabel = bindingLabel;
        if (string.Equals(propertyName, "action", StringComparison.OrdinalIgnoreCase))
        {
            effectiveLabel = string.Equals(targetKind, "page", StringComparison.OrdinalIgnoreCase)
                ? "showPage"
                : "onClick";
        }

        bindings[effectiveLabel] = targetValue!;
    }

    private static bool TryExtractClientActionTarget(
        JsonElement actionElement,
        out string? targetKind,
        out string? targetValue)
    {
        targetKind = null;
        targetValue = null;

        var directPage = TryReadStringProperty(actionElement, "page");
        var directMicroflow = TryReadStringProperty(actionElement, "microflow");
        var directNanoflow = TryReadStringProperty(actionElement, "nanoflow");
        var pageFromSettings = TryReadNestedStringProperty(actionElement, "pageSettings", "page");
        var microflowFromSettings = TryReadNestedStringProperty(actionElement, "microflowSettings", "microflow");
        var nanoflowFromSettings = TryReadNestedStringProperty(actionElement, "nanoflowSettings", "nanoflow");

        var pageTarget = !string.IsNullOrWhiteSpace(pageFromSettings) ? pageFromSettings : directPage;
        if (!string.IsNullOrWhiteSpace(pageTarget))
        {
            targetKind = "page";
            targetValue = NormalizeInlineText(pageTarget!, 140);
            return true;
        }

        var microflowTarget = !string.IsNullOrWhiteSpace(microflowFromSettings) ? microflowFromSettings : directMicroflow;
        if (!string.IsNullOrWhiteSpace(microflowTarget))
        {
            targetKind = "microflow";
            targetValue = NormalizeInlineText(microflowTarget!, 140);
            return true;
        }

        var nanoflowTarget = !string.IsNullOrWhiteSpace(nanoflowFromSettings) ? nanoflowFromSettings : directNanoflow;
        if (!string.IsNullOrWhiteSpace(nanoflowTarget))
        {
            targetKind = "nanoflow";
            targetValue = NormalizeInlineText(nanoflowTarget!, 140);
            return true;
        }

        return false;
    }

    private static bool TryExtractWidgetSource(JsonElement sourceElement, out string source)
    {
        source = string.Empty;

        var microflow =
            TryReadNestedStringProperty(sourceElement, "microflowSettings", "microflow") ??
            TryReadNestedStringProperty(sourceElement, "dataSourceMicroflowSettings", "microflow") ??
            TryReadStringProperty(sourceElement, "microflow");
        if (!string.IsNullOrWhiteSpace(microflow))
        {
            source = NormalizeInlineText(microflow, 140);
            return true;
        }

        var nanoflow = TryReadStringProperty(sourceElement, "nanoflow");
        if (!string.IsNullOrWhiteSpace(nanoflow))
        {
            source = NormalizeInlineText(nanoflow, 140);
            return true;
        }

        var sourceVariableName = TryReadNestedStringProperty(sourceElement, "sourceVariable", "pageParameter") ??
                                 TryReadNestedStringProperty(sourceElement, "sourceVariable", "localVariable") ??
                                 TryReadNestedStringProperty(sourceElement, "sourceVariable", "widget");
        if (!string.IsNullOrWhiteSpace(sourceVariableName))
        {
            source = NormalizeInlineText(sourceVariableName, 140);
            return true;
        }

        var entity = TryReadNestedStringProperty(sourceElement, "entityRef", "entity");
        if (!string.IsNullOrWhiteSpace(entity))
        {
            source = NormalizeInlineText(entity, 140);
            return true;
        }

        return false;
    }

    private static List<string> BuildWidgetBindingChanges(
        IReadOnlyDictionary<string, string> previousBindings,
        IReadOnlyDictionary<string, string> currentBindings)
    {
        var changes = new List<string>();
        var keys = previousBindings.Keys
            .Union(currentBindings.Keys, StringComparer.OrdinalIgnoreCase)
            .OrderBy(key => key, StringComparer.OrdinalIgnoreCase)
            .ToArray();

        foreach (var key in keys)
        {
            previousBindings.TryGetValue(key, out var previousValue);
            currentBindings.TryGetValue(key, out var currentValue);
            if (string.Equals(previousValue, currentValue, StringComparison.Ordinal))
            {
                continue;
            }

            if (string.IsNullOrWhiteSpace(previousValue))
            {
                changes.Add($"{key}={currentValue}");
                continue;
            }

            if (string.IsNullOrWhiteSpace(currentValue))
            {
                changes.Add($"{key} removed");
                continue;
            }

            changes.Add($"{key} {previousValue}->{currentValue}");
        }

        return changes;
    }

    private static string? BuildWidgetPropertyChangeSummary(JsonElement previousWidget, JsonElement currentWidget)
    {
        if (previousWidget.ValueKind != JsonValueKind.Object || currentWidget.ValueKind != JsonValueKind.Object)
        {
            return null;
        }

        var modelType =
            TryReadStringProperty(currentWidget, "$Type") ??
            TryReadStringProperty(previousWidget, "$Type");
        var previousProperties = previousWidget
            .EnumerateObject()
            .Where(property =>
                !IgnoredDetailFields.Contains(property.Name) &&
                !IsWidgetBindingProperty(property.Name))
            .ToDictionary(property => property.Name, property => property.Value, StringComparer.Ordinal);
        var currentProperties = currentWidget
            .EnumerateObject()
            .Where(property =>
                !IgnoredDetailFields.Contains(property.Name) &&
                !IsWidgetBindingProperty(property.Name))
            .ToDictionary(property => property.Name, property => property.Value, StringComparer.Ordinal);
        var parts = new List<string>();

        foreach (var (propertyName, currentValue) in currentProperties)
        {
            if (!previousProperties.TryGetValue(propertyName, out var previousValue))
            {
                parts.Add($"{propertyName} added");
                continue;
            }

            if (!ElementsSemanticallyEqual(previousValue, currentValue, propertyName, modelType))
            {
                parts.Add(DescribePropertyChange(propertyName, previousValue, currentValue));
            }
        }

        foreach (var propertyName in previousProperties.Keys)
        {
            if (!currentProperties.ContainsKey(propertyName))
            {
                parts.Add($"{propertyName} removed");
            }
        }

        if (parts.Count == 0)
        {
            return null;
        }

        const int maxParts = 2;
        var visible = parts.Take(maxParts).ToList();
        var remaining = parts.Count - visible.Count;
        if (remaining > 0)
        {
            visible.Add($"+{remaining} more");
        }

        return string.Join(", ", visible);
    }

    private static bool IsWidgetBindingProperty(string propertyName)
    {
        return string.Equals(propertyName, "action", StringComparison.OrdinalIgnoreCase) ||
               string.Equals(propertyName, "onChangeAction", StringComparison.OrdinalIgnoreCase) ||
               string.Equals(propertyName, "onClickAction", StringComparison.OrdinalIgnoreCase) ||
               string.Equals(propertyName, "onEnterAction", StringComparison.OrdinalIgnoreCase) ||
               string.Equals(propertyName, "onLeaveAction", StringComparison.OrdinalIgnoreCase) ||
               string.Equals(propertyName, "onEnterKeyPressAction", StringComparison.OrdinalIgnoreCase) ||
               string.Equals(propertyName, "clickAction", StringComparison.OrdinalIgnoreCase) ||
               string.Equals(propertyName, "pullDownAction", StringComparison.OrdinalIgnoreCase) ||
               string.Equals(propertyName, "dataSource", StringComparison.OrdinalIgnoreCase) ||
               string.Equals(propertyName, "selectorSource", StringComparison.OrdinalIgnoreCase) ||
               string.Equals(propertyName, "pageSettings", StringComparison.OrdinalIgnoreCase) ||
               string.Equals(propertyName, "selectPageSettings", StringComparison.OrdinalIgnoreCase) ||
               string.Equals(propertyName, "gotoPageSettings", StringComparison.OrdinalIgnoreCase);
    }

    private static string[] CollectDistinctPageActionTargets(IEnumerable<PageClientActionInfo> actions)
    {
        return actions
            .SelectMany(action => action.Targets)
            .Where(target => !string.IsNullOrWhiteSpace(target))
            .Distinct(StringComparer.OrdinalIgnoreCase)
            .OrderBy(target => target, StringComparer.OrdinalIgnoreCase)
            .ToArray();
    }

    private static string? BuildPageWidgetSummaryDetails(
        JsonElement? workingResource,
        JsonElement? headResource)
    {
        var workingWidgetCounts = workingResource is null
            ? new Dictionary<string, int>(StringComparer.OrdinalIgnoreCase)
            : CollectPageWidgetTypeCounts(workingResource.Value);
        var headWidgetCounts = headResource is null
            ? new Dictionary<string, int>(StringComparer.OrdinalIgnoreCase)
            : CollectPageWidgetTypeCounts(headResource.Value);
        var workingFunctionalWidgetCounts = BuildFunctionalPageWidgetCounts(workingWidgetCounts);
        var headFunctionalWidgetCounts = BuildFunctionalPageWidgetCounts(headWidgetCounts);

        var workingTotal = workingWidgetCounts.Values.Sum();
        var headTotal = headWidgetCounts.Values.Sum();
        if (workingTotal == 0 && headTotal == 0)
        {
            return null;
        }

        if (workingResource is not null && headResource is not null)
        {
            return null;
        }

        var details = new List<string>();
        if (workingTotal > 0)
        {
            details.Add($"widgets used ({workingTotal}): {FormatCounterList(workingWidgetCounts)}");
            if (workingFunctionalWidgetCounts.Count > 0)
            {
                var total = workingFunctionalWidgetCounts.Values.Sum();
                details.Add($"functional widgets ({total}): {FormatCounterList(workingFunctionalWidgetCounts, maxEntries: 10)}");
            }
        }

        if (headTotal > 0)
        {
            details.Add($"widgets before deletion ({headTotal}): {FormatCounterList(headWidgetCounts)}");
            if (headFunctionalWidgetCounts.Count > 0)
            {
                var total = headFunctionalWidgetCounts.Values.Sum();
                details.Add($"functional widgets before deletion ({total}): {FormatCounterList(headFunctionalWidgetCounts, maxEntries: 10)}");
            }
        }

        return details.Count == 0 ? null : string.Join("; ", details);
    }

    private static Dictionary<string, int> CollectPageWidgetTypeCounts(JsonElement pageResource)
    {
        if (!TryReadProperty(pageResource, "layoutCall", out var layoutCall) ||
            layoutCall.ValueKind != JsonValueKind.Object)
        {
            return new Dictionary<string, int>(StringComparer.OrdinalIgnoreCase);
        }

        var widgetCounts = new Dictionary<string, int>(StringComparer.OrdinalIgnoreCase);
        var stack = new Stack<JsonElement>();
        stack.Push(layoutCall);

        while (stack.Count > 0)
        {
            var current = stack.Pop();
            switch (current.ValueKind)
            {
                case JsonValueKind.Object:
                {
                    var modelType = TryReadStringProperty(current, "$Type");
                    if (IsPageWidgetModelType(modelType))
                    {
                        IncrementCount(widgetCounts, ShortTypeName(modelType!));
                    }

                    foreach (var property in current.EnumerateObject())
                    {
                        stack.Push(property.Value);
                    }

                    break;
                }

                case JsonValueKind.Array:
                    foreach (var item in current.EnumerateArray())
                    {
                        stack.Push(item);
                    }

                    break;
            }
        }

        return widgetCounts;
    }

    private static Dictionary<string, int> BuildFunctionalPageWidgetCounts(IReadOnlyDictionary<string, int> widgetCounts)
    {
        var functionalCounts = new Dictionary<string, int>(StringComparer.OrdinalIgnoreCase);
        foreach (var (widgetType, count) in widgetCounts)
        {
            if (count <= 0 ||
                !FunctionalPageWidgetTypeMap.TryGetValue(widgetType, out var normalizedWidgetType))
            {
                continue;
            }

            if (functionalCounts.TryGetValue(normalizedWidgetType, out var existing))
            {
                functionalCounts[normalizedWidgetType] = existing + count;
                continue;
            }

            functionalCounts[normalizedWidgetType] = count;
        }

        return functionalCounts;
    }

    private static bool IsPageWidgetModelType(string? modelType)
    {
        if (string.IsNullOrWhiteSpace(modelType) ||
            !modelType.StartsWith("Pages$", StringComparison.OrdinalIgnoreCase))
        {
            return false;
        }

        if (NonWidgetPageModelTypes.Contains(modelType))
        {
            return false;
        }

        if (IsPageClientActionType(modelType))
        {
            return false;
        }

        return true;
    }

    private static List<PageClientActionInfo> CollectPageClientActions(JsonElement pageResource)
    {
        var actions = new List<PageClientActionInfo>();
        var stack = new Stack<JsonElement>();
        stack.Push(pageResource);

        while (stack.Count > 0)
        {
            var current = stack.Pop();
            switch (current.ValueKind)
            {
                case JsonValueKind.Object:
                {
                    var modelType = TryReadStringProperty(current, "$Type");
                    if (IsPageClientActionType(modelType))
                    {
                        var targets = new List<string>();
                        AddPageActionTarget(targets, "microflow", TryReadStringProperty(current, "microflow"));
                        AddPageActionTarget(targets, "nanoflow", TryReadStringProperty(current, "nanoflow"));
                        AddPageActionTarget(targets, "page", TryReadStringProperty(current, "page"));
                        AddPageActionTarget(targets, "microflow", TryReadNestedStringProperty(current, "microflowSettings", "microflow"));
                        AddPageActionTarget(targets, "nanoflow", TryReadNestedStringProperty(current, "nanoflowSettings", "nanoflow"));
                        AddPageActionTarget(targets, "page", TryReadNestedStringProperty(current, "pageSettings", "page"));

                        actions.Add(new PageClientActionInfo(
                            ShortTypeName(modelType!),
                            targets
                                .Distinct(StringComparer.OrdinalIgnoreCase)
                                .OrderBy(target => target, StringComparer.OrdinalIgnoreCase)
                                .ToArray()));
                    }

                    foreach (var property in current.EnumerateObject())
                    {
                        stack.Push(property.Value);
                    }

                    break;
                }

                case JsonValueKind.Array:
                    foreach (var item in current.EnumerateArray())
                    {
                        stack.Push(item);
                    }

                    break;
            }
        }

        return actions;
    }

    private static bool IsPageClientActionType(string? modelType)
    {
        if (string.IsNullOrWhiteSpace(modelType))
        {
            return false;
        }

        return modelType.StartsWith("Pages$", StringComparison.OrdinalIgnoreCase) &&
               modelType.EndsWith("ClientAction", StringComparison.OrdinalIgnoreCase) &&
               !string.Equals(modelType, NoClientActionModelType, StringComparison.OrdinalIgnoreCase);
    }

    private static void AddPageActionTarget(ICollection<string> targets, string label, string? value)
    {
        if (string.IsNullOrWhiteSpace(value))
        {
            return;
        }

        targets.Add($"{label}={NormalizeInlineText(value, 140)}");
    }

    private static string? BuildPageAllowedRolesDetails(
        JsonElement? workingResource,
        JsonElement? headResource,
        DumpSnapshot workingSnapshot,
        DumpSnapshot headSnapshot)
    {
        var workingRoles = ReadStringArrayProperty(workingResource, "allowedRoles");
        var headRoles = ReadStringArrayProperty(headResource, "allowedRoles");
        if (workingRoles.Length == 0 && headRoles.Length == 0)
        {
            return null;
        }

        var roleNames = BuildRoleNameLookup(workingSnapshot, headSnapshot);

        var workingSet = new HashSet<string>(workingRoles, StringComparer.OrdinalIgnoreCase);
        var headSet = new HashSet<string>(headRoles, StringComparer.OrdinalIgnoreCase);
        if (workingSet.SetEquals(headSet))
        {
            return null;
        }

        var kept = workingSet
            .Intersect(headSet, StringComparer.OrdinalIgnoreCase)
            .Select(role => ResolveRoleLabel(role, roleNames))
            .Distinct(StringComparer.OrdinalIgnoreCase)
            .OrderBy(role => role, StringComparer.OrdinalIgnoreCase)
            .ToArray();

        var removed = headSet
            .Except(workingSet, StringComparer.OrdinalIgnoreCase)
            .Select(role => ResolveRoleLabel(role, roleNames))
            .Distinct(StringComparer.OrdinalIgnoreCase)
            .OrderBy(role => role, StringComparer.OrdinalIgnoreCase)
            .ToArray();

        var added = workingSet
            .Except(headSet, StringComparer.OrdinalIgnoreCase)
            .Select(role => ResolveRoleLabel(role, roleNames))
            .Distinct(StringComparer.OrdinalIgnoreCase)
            .OrderBy(role => role, StringComparer.OrdinalIgnoreCase)
            .ToArray();

        var parts = new List<string>
        {
            $"allowedRoles count {headRoles.Length}->{workingRoles.Length}"
        };

        if (kept.Length > 0)
        {
            parts.Add($"allowedRoles kept ({kept.Length}): {FormatNameList(kept)}");
        }

        if (removed.Length > 0)
        {
            parts.Add($"allowedRoles removed ({removed.Length}): {FormatNameList(removed)}");
        }

        if (added.Length > 0)
        {
            parts.Add($"allowedRoles added ({added.Length}): {FormatNameList(added)}");
        }

        return string.Join("; ", parts);
    }

    private static Dictionary<string, string> BuildRoleNameLookup(
        DumpSnapshot workingSnapshot,
        DumpSnapshot headSnapshot)
    {
        var roleNames = new Dictionary<string, string>(StringComparer.OrdinalIgnoreCase);
        AddRoleNames(workingSnapshot, roleNames);
        AddRoleNames(headSnapshot, roleNames);
        return roleNames;
    }

    private static void AddRoleNames(DumpSnapshot snapshot, Dictionary<string, string> roleNames)
    {
        foreach (var objectElement in snapshot.ObjectsById.Values)
        {
            var modelType = TryReadStringProperty(objectElement, "$Type");
            if (!string.Equals(modelType, UserRoleModelType, StringComparison.OrdinalIgnoreCase))
            {
                continue;
            }

            var roleId = TryReadStringProperty(objectElement, "$ID");
            if (string.IsNullOrWhiteSpace(roleId))
            {
                continue;
            }

            var roleLabel =
                TryReadStringProperty(objectElement, "$QualifiedName") ??
                TryReadStringProperty(objectElement, "name") ??
                roleId;

            roleNames[roleId] = roleLabel;
        }
    }

    private static string ResolveRoleLabel(string roleToken, Dictionary<string, string> roleNames)
    {
        if (string.IsNullOrWhiteSpace(roleToken))
        {
            return "<unknown>";
        }

        return roleNames.TryGetValue(roleToken, out var roleLabel)
            ? roleLabel
            : roleToken;
    }

    private static string[] ReadStringArrayProperty(JsonElement? resourceObject, string propertyName)
    {
        if (resourceObject is null)
        {
            return Array.Empty<string>();
        }

        if (!TryReadProperty(resourceObject.Value, propertyName, out var propertyElement) ||
            propertyElement.ValueKind != JsonValueKind.Array)
        {
            return Array.Empty<string>();
        }

        return propertyElement
            .EnumerateArray()
            .Select(value => value.ValueKind == JsonValueKind.String ? value.GetString() : value.GetRawText())
            .Where(value => !string.IsNullOrWhiteSpace(value))
            .Select(value => value!.Trim())
            .Distinct(StringComparer.OrdinalIgnoreCase)
            .ToArray();
    }

    private static string? BuildGenericResourceDetails(
        string changeType,
        string modelType,
        JsonElement? workingResource,
        JsonElement? headResource)
    {
        var resourceObject = string.Equals(changeType, "Deleted", StringComparison.OrdinalIgnoreCase)
            ? headResource ?? workingResource
            : workingResource ?? headResource;
        if (resourceObject is null)
        {
            return null;
        }

        var details = new List<string>
        {
            $"modelType={ShortTypeName(modelType)}"
        };

        var metadata = new List<string>();
        foreach (var propertyName in GenericScalarDetailProperties)
        {
            var maxLength = string.Equals(propertyName, "documentation", StringComparison.OrdinalIgnoreCase) ? 100 : 140;
            AppendOption(metadata, propertyName, TryReadStringProperty(resourceObject.Value, propertyName), maxLength);
        }

        foreach (var (propertyName, label) in GenericArrayCountProperties)
        {
            var count = TryGetArrayPropertyCount(resourceObject.Value, propertyName);
            if (count is > 0)
            {
                metadata.Add($"{label}={count}");
            }
        }

        if (metadata.Count > 0)
        {
            details.Add($"resource metadata: {string.Join(", ", metadata)}");
        }

        var nestedSummary = BuildNestedTypeSummary(resourceObject.Value);
        if (!string.IsNullOrWhiteSpace(nestedSummary))
        {
            details.Add(nestedSummary);
        }

        if (details.Count == 1)
        {
            if (string.Equals(changeType, "Added", StringComparison.OrdinalIgnoreCase))
            {
                details.Add("resource created");
            }
            else if (string.Equals(changeType, "Deleted", StringComparison.OrdinalIgnoreCase))
            {
                details.Add("resource before deletion");
            }
            else
            {
                details.Add("resource updated");
            }
        }

        return string.Join("; ", details);
    }

    private static string? BuildNestedTypeSummary(JsonElement resourceObject, int maxTypes = 6)
    {
        var rootType = TryReadStringProperty(resourceObject, "$Type");
        var nestedTypeCounts = new Dictionary<string, int>(StringComparer.OrdinalIgnoreCase);
        var stack = new Stack<JsonElement>();
        stack.Push(resourceObject);

        while (stack.Count > 0)
        {
            var current = stack.Pop();
            switch (current.ValueKind)
            {
                case JsonValueKind.Object:
                {
                    var modelType = TryReadStringProperty(current, "$Type");
                    if (!string.IsNullOrWhiteSpace(modelType) &&
                        !string.Equals(modelType, rootType, StringComparison.OrdinalIgnoreCase))
                    {
                        IncrementCount(nestedTypeCounts, ShortTypeName(modelType));
                    }

                    foreach (var property in current.EnumerateObject())
                    {
                        stack.Push(property.Value);
                    }

                    break;
                }

                case JsonValueKind.Array:
                    foreach (var item in current.EnumerateArray())
                    {
                        stack.Push(item);
                    }

                    break;
            }
        }

        if (nestedTypeCounts.Count == 0)
        {
            return null;
        }

        var total = nestedTypeCounts.Values.Sum();
        return $"nested types ({total}): {FormatCounterList(nestedTypeCounts, maxEntries: maxTypes)}";
    }

    private static int? TryGetArrayPropertyCount(JsonElement element, string propertyName)
    {
        if (!TryReadProperty(element, propertyName, out var propertyElement) ||
            propertyElement.ValueKind != JsonValueKind.Array)
        {
            return null;
        }

        return propertyElement.GetArrayLength();
    }

    private static Dictionary<string, string> CollectDomainAttributes(JsonElement entityObject)
    {
        var attributes = new Dictionary<string, string>(StringComparer.OrdinalIgnoreCase);
        if (!TryReadProperty(entityObject, "attributes", out var attributesElement) ||
            attributesElement.ValueKind != JsonValueKind.Array)
        {
            return attributes;
        }

        foreach (var attribute in attributesElement.EnumerateArray())
        {
            if (attribute.ValueKind != JsonValueKind.Object)
            {
                continue;
            }

            var modelType = TryReadStringProperty(attribute, "$Type");
            if (!string.Equals(modelType, DomainAttributeModelType, StringComparison.OrdinalIgnoreCase))
            {
                continue;
            }

            var key =
                TryReadStringProperty(attribute, "$ID") ??
                TryReadStringProperty(attribute, "$QualifiedName") ??
                TryReadStringProperty(attribute, "name") ??
                $"attribute_{attributes.Count + 1}";

            var name =
                TryReadStringProperty(attribute, "name") ??
                TryReadStringProperty(attribute, "$QualifiedName") ??
                key;

            attributes[key] = NormalizeInlineText(name, 120);
        }

        return attributes;
    }

    private static string FormatCounterList(Dictionary<string, int> counts, int maxEntries = 8)
    {
        var ordered = counts
            .OrderByDescending(pair => pair.Value)
            .ThenBy(pair => pair.Key, StringComparer.OrdinalIgnoreCase)
            .ToArray();

        var visible = ordered.Take(maxEntries).Select(pair => $"{pair.Key} x{pair.Value}").ToList();
        var remaining = ordered.Length - visible.Count;
        if (remaining > 0)
        {
            visible.Add($"+{remaining} more");
        }

        return string.Join(", ", visible);
    }

    private static string FormatNameList(IEnumerable<string> names, int maxEntries = 10)
    {
        var ordered = names
            .Where(name => !string.IsNullOrWhiteSpace(name))
            .Distinct(StringComparer.OrdinalIgnoreCase)
            .OrderBy(name => name, StringComparer.OrdinalIgnoreCase)
            .ToArray();

        if (ordered.Length == 0)
        {
            return "<none>";
        }

        var visible = ordered.Take(maxEntries).ToList();
        var remaining = ordered.Length - visible.Count;
        if (remaining > 0)
        {
            visible.Add($"+{remaining} more");
        }

        return string.Join(", ", visible);
    }

    private static string FormatRenameList(
        IEnumerable<(string Previous, string Current)> renames,
        int maxEntries = 10)
    {
        var ordered = renames
            .Where(rename =>
                !string.IsNullOrWhiteSpace(rename.Previous) &&
                !string.IsNullOrWhiteSpace(rename.Current))
            .Select(rename => $"{NormalizeInlineText(rename.Previous, 80)}->{NormalizeInlineText(rename.Current, 80)}")
            .Distinct(StringComparer.OrdinalIgnoreCase)
            .OrderBy(rename => rename, StringComparer.OrdinalIgnoreCase)
            .ToArray();

        if (ordered.Length == 0)
        {
            return "<none>";
        }

        var visible = ordered.Take(maxEntries).ToList();
        var remaining = ordered.Length - visible.Count;
        if (remaining > 0)
        {
            visible.Add($"+{remaining} more");
        }

        return string.Join(", ", visible);
    }

    private static string ShortTypeName(string modelType)
    {
        if (string.IsNullOrWhiteSpace(modelType))
        {
            return "<unknown>";
        }

        var separatorIndex = modelType.IndexOf('$');
        return separatorIndex >= 0 && separatorIndex < modelType.Length - 1
            ? modelType[(separatorIndex + 1)..]
            : modelType;
    }

    private static string ShortName(string? value)
    {
        if (string.IsNullOrWhiteSpace(value))
        {
            return "<unknown>";
        }

        var trimmed = value.Trim();
        var separatorIndex = trimmed.LastIndexOf('.');
        return separatorIndex >= 0 && separatorIndex < trimmed.Length - 1
            ? trimmed[(separatorIndex + 1)..]
            : trimmed;
    }

    private static bool TryReadProperty(JsonElement element, string propertyName, out JsonElement value)
    {
        foreach (var property in element.EnumerateObject())
        {
            if (string.Equals(property.Name, propertyName, StringComparison.OrdinalIgnoreCase))
            {
                value = property.Value;
                return true;
            }
        }

        value = default;
        return false;
    }

    private static void IncrementCount(Dictionary<string, int> counts, string key)
    {
        if (counts.TryGetValue(key, out var existing))
        {
            counts[key] = existing + 1;
            return;
        }

        counts[key] = 1;
    }

    private static string? TryReadNestedStringProperty(
        JsonElement element,
        string objectPropertyName,
        string nestedPropertyName)
    {
        if (!TryReadProperty(element, objectPropertyName, out var objectElement) ||
            objectElement.ValueKind != JsonValueKind.Object)
        {
            return null;
        }

        return TryReadStringProperty(objectElement, nestedPropertyName);
    }

    private static string? TryReadNestedTranslatableTextProperty(
        JsonElement element,
        string objectPropertyName,
        string nestedTextPropertyName,
        string preferredLanguageCode = "en_US")
    {
        if (!TryReadProperty(element, objectPropertyName, out var objectElement) ||
            objectElement.ValueKind != JsonValueKind.Object)
        {
            return null;
        }

        if (!TryReadProperty(objectElement, nestedTextPropertyName, out var textElement))
        {
            return null;
        }

        return TryReadTranslatedText(textElement, preferredLanguageCode);
    }

    private static string? TryReadTranslatableTextProperty(
        JsonElement element,
        string propertyName,
        string preferredLanguageCode = "en_US")
    {
        if (!TryReadProperty(element, propertyName, out var textElement))
        {
            return null;
        }

        return TryReadTranslatedText(textElement, preferredLanguageCode);
    }

    private static string? TryReadTranslatedText(
        JsonElement textElement,
        string preferredLanguageCode = "en_US")
    {
        if (textElement.ValueKind == JsonValueKind.String)
        {
            return textElement.GetString();
        }

        if (textElement.ValueKind != JsonValueKind.Object)
        {
            return null;
        }

        if (TryReadProperty(textElement, "translations", out var translationsElement) &&
            translationsElement.ValueKind == JsonValueKind.Array)
        {
            string? fallbackText = null;
            foreach (var translation in translationsElement.EnumerateArray())
            {
                if (translation.ValueKind != JsonValueKind.Object)
                {
                    continue;
                }

                var translationText = TryReadStringProperty(translation, "text");
                if (string.IsNullOrWhiteSpace(translationText))
                {
                    continue;
                }

                fallbackText ??= translationText;
                var languageCode = TryReadStringProperty(translation, "languageCode");
                if (string.Equals(languageCode, preferredLanguageCode, StringComparison.OrdinalIgnoreCase))
                {
                    return translationText;
                }
            }

            return fallbackText;
        }

        return TryReadStringProperty(textElement, "text");
    }

    private static bool IsFlowModelType(string? modelType)
    {
        if (string.IsNullOrWhiteSpace(modelType))
        {
            return false;
        }

        return string.Equals(modelType, MicroflowModelType, StringComparison.OrdinalIgnoreCase) ||
               string.Equals(modelType, NanoflowModelType, StringComparison.OrdinalIgnoreCase) ||
               string.Equals(modelType, LegacyNanoflowModelType, StringComparison.OrdinalIgnoreCase) ||
               string.Equals(modelType, RuleModelType, StringComparison.OrdinalIgnoreCase);
    }

    private static bool IsPageLikeModelType(string? modelType)
    {
        if (string.IsNullOrWhiteSpace(modelType))
        {
            return false;
        }

        return string.Equals(modelType, PageModelType, StringComparison.OrdinalIgnoreCase) ||
               string.Equals(modelType, PageSnippetModelType, StringComparison.OrdinalIgnoreCase) ||
               string.Equals(modelType, PageTemplateModelType, StringComparison.OrdinalIgnoreCase) ||
               string.Equals(modelType, PageBuildingBlockModelType, StringComparison.OrdinalIgnoreCase) ||
               string.Equals(modelType, PageLayoutModelType, StringComparison.OrdinalIgnoreCase);
    }

    private static bool IsEnumerationModelType(string? modelType)
    {
        if (string.IsNullOrWhiteSpace(modelType))
        {
            return false;
        }

        return string.Equals(modelType, DomainEnumerationModelType, StringComparison.OrdinalIgnoreCase) ||
               string.Equals(modelType, LegacyDomainEnumerationModelType, StringComparison.OrdinalIgnoreCase);
    }

    private static string? ResolveOwningResourceId(DumpSnapshot snapshot, string objectId)
    {
        if (string.IsNullOrWhiteSpace(objectId))
        {
            return null;
        }

        var visited = new HashSet<string>(StringComparer.OrdinalIgnoreCase);
        var currentId = objectId;

        while (!string.IsNullOrWhiteSpace(currentId) && visited.Add(currentId))
        {
            if (snapshot.ResourcesById.ContainsKey(currentId))
            {
                return currentId;
            }

            if (!snapshot.ParentById.TryGetValue(currentId, out var parentId) ||
                string.IsNullOrWhiteSpace(parentId))
            {
                break;
            }

            currentId = parentId;
        }

        return null;
    }

    private static ResourceDescriptor? ResolveOwnerDescriptor(
        string resourceId,
        DumpSnapshot workingSnapshot,
        DumpSnapshot headSnapshot)
    {
        if (workingSnapshot.ResourcesById.TryGetValue(resourceId, out var working))
        {
            return working;
        }

        return headSnapshot.ResourcesById.TryGetValue(resourceId, out var head)
            ? head
            : null;
    }

    private static DumpSnapshot BuildSnapshot(JsonElement root)
    {
        var snapshot = new DumpSnapshot();
        var stack = new Stack<JsonElement>();
        stack.Push(root);

        while (stack.Count > 0)
        {
            var current = stack.Pop();
            switch (current.ValueKind)
            {
                case JsonValueKind.Object:
                {
                    var objectId = TryReadStringProperty(current, "$ID");
                    if (!string.IsNullOrWhiteSpace(objectId))
                    {
                        var clone = current.Clone();
                        snapshot.ObjectsById[objectId] = clone;

                        var containerId = TryReadStringProperty(current, "$ContainerID");
                        if (!string.IsNullOrWhiteSpace(containerId) &&
                            !string.Equals(containerId, objectId, StringComparison.OrdinalIgnoreCase))
                        {
                            snapshot.ParentById[objectId] = containerId;
                        }

                        var modelType = TryReadStringProperty(current, "$Type");
                        var containerProperty = TryReadStringProperty(current, "$ContainerProperty");
                        if (IsTrackableResource(modelType, containerProperty))
                        {
                            var descriptor = BuildResourceDescriptor(clone);
                            if (descriptor is not null)
                            {
                                snapshot.ResourcesById[objectId] = descriptor;
                            }
                        }
                    }

                    foreach (var property in current.EnumerateObject())
                    {
                        stack.Push(property.Value);
                    }

                    break;
                }

                case JsonValueKind.Array:
                    foreach (var item in current.EnumerateArray())
                    {
                        stack.Push(item);
                    }

                    break;
            }
        }

        return snapshot;
    }

    private static bool IsTrackableResource(string? modelType, string? containerProperty)
    {
        if (string.IsNullOrWhiteSpace(modelType))
        {
            return false;
        }

        if (!string.IsNullOrWhiteSpace(containerProperty) &&
            TrackableContainerProperties.Contains(containerProperty))
        {
            return true;
        }

        return TrackableDomainModelTypes.Contains(modelType);
    }

    private static ResourceDescriptor? BuildResourceDescriptor(JsonElement element)
    {
        var resourceId = TryReadStringProperty(element, "$ID");
        var modelType = TryReadStringProperty(element, "$Type");

        if (string.IsNullOrWhiteSpace(resourceId) || string.IsNullOrWhiteSpace(modelType))
        {
            return null;
        }

        var elementType = ResolveElementType(modelType, element);
        var elementName = ResolveElementName(element);
        if (string.Equals(elementName, "<unnamed>", StringComparison.Ordinal))
        {
            var shortId = resourceId.Length > 8 ? resourceId[..8] : resourceId;
            elementName = $"{elementType} [{shortId}]";
        }

        return new ResourceDescriptor(resourceId, modelType, elementType, elementName, element);
    }

    private static string ResolveElementType(string modelType, JsonElement element)
    {
        var elementType = ResolveElementType(modelType);
        if (string.Equals(elementType, "Entity", StringComparison.OrdinalIgnoreCase) &&
            IsNonPersistentEntity(element))
        {
            return NonPersistentEntityElementType;
        }

        return elementType;
    }

    private static string ResolveElementType(string modelType)
    {
        if (ElementTypeOverrides.TryGetValue(modelType, out var overrideType))
        {
            return overrideType;
        }

        var separatorIndex = modelType.IndexOf('$');
        var typeName = separatorIndex >= 0 && separatorIndex < modelType.Length - 1
            ? modelType[(separatorIndex + 1)..]
            : modelType;

        if (typeName.EndsWith("Document", StringComparison.OrdinalIgnoreCase) &&
            typeName.Length > "Document".Length)
        {
            return typeName[..^"Document".Length];
        }

        return typeName;
    }

    private static string ResolveElementName(JsonElement element)
    {
        foreach (var propertyName in NameFields)
        {
            var value = TryReadStringProperty(element, propertyName);
            if (!string.IsNullOrWhiteSpace(value))
            {
                return value;
            }
        }

        return "<unnamed>";
    }

    private static bool IsSemanticNestedObjectChange(
        DumpSnapshot workingSnapshot,
        DumpSnapshot headSnapshot,
        string objectId,
        string nestedChangeType)
    {
        if (string.IsNullOrWhiteSpace(objectId))
        {
            return false;
        }

        if (string.Equals(nestedChangeType, "Added", StringComparison.OrdinalIgnoreCase))
        {
            if (!workingSnapshot.ObjectsById.TryGetValue(objectId, out var workingObject))
            {
                return false;
            }

            return !IsLayoutOnlyNestedObject(workingObject);
        }

        if (string.Equals(nestedChangeType, "Deleted", StringComparison.OrdinalIgnoreCase))
        {
            if (!headSnapshot.ObjectsById.TryGetValue(objectId, out var headObject))
            {
                return false;
            }

            return !IsLayoutOnlyNestedObject(headObject);
        }

        if (!workingSnapshot.ObjectsById.TryGetValue(objectId, out var workingModifiedObject) ||
            !headSnapshot.ObjectsById.TryGetValue(objectId, out var headModifiedObject))
        {
            return false;
        }

        return !ElementsSemanticallyEqual(workingModifiedObject, headModifiedObject);
    }

    private static bool IsLayoutOnlyNestedObject(JsonElement element)
    {
        var modelType = TryReadStringProperty(element, "$Type");
        return !string.IsNullOrWhiteSpace(modelType) &&
               LayoutOnlyNestedModelTypes.Contains(modelType);
    }

    private static bool ElementsSemanticallyEqual(
        JsonElement left,
        JsonElement right,
        string? currentPropertyName = null,
        string? ownerModelType = null)
    {
        if (left.ValueKind != right.ValueKind)
        {
            return false;
        }

        switch (left.ValueKind)
        {
            case JsonValueKind.Object:
            {
                var currentModelType =
                    TryReadStringProperty(left, "$Type") ??
                    TryReadStringProperty(right, "$Type") ??
                    ownerModelType;

                var leftProperties = left
                    .EnumerateObject()
                    .Where(property => !ShouldIgnorePropertyForSemanticDiff(currentModelType, property.Name))
                    .ToDictionary(property => property.Name, property => property.Value, StringComparer.Ordinal);

                var rightProperties = right
                    .EnumerateObject()
                    .Where(property => !ShouldIgnorePropertyForSemanticDiff(currentModelType, property.Name))
                    .ToDictionary(property => property.Name, property => property.Value, StringComparer.Ordinal);

                if (leftProperties.Count != rightProperties.Count)
                {
                    return false;
                }

                foreach (var (propertyName, leftValue) in leftProperties)
                {
                    if (!rightProperties.TryGetValue(propertyName, out var rightValue))
                    {
                        return false;
                    }

                    if (!ElementsSemanticallyEqual(leftValue, rightValue, propertyName, currentModelType))
                    {
                        return false;
                    }
                }

                return true;
            }

            case JsonValueKind.Array:
                return ArraysSemanticallyEqual(left, right, currentPropertyName, ownerModelType);

            case JsonValueKind.String:
                return string.Equals(left.GetString(), right.GetString(), StringComparison.Ordinal);

            case JsonValueKind.Number:
                return string.Equals(left.GetRawText(), right.GetRawText(), StringComparison.Ordinal);

            case JsonValueKind.True:
            case JsonValueKind.False:
                return left.GetBoolean() == right.GetBoolean();

            case JsonValueKind.Null:
            case JsonValueKind.Undefined:
                return true;

            default:
                return string.Equals(left.GetRawText(), right.GetRawText(), StringComparison.Ordinal);
        }
    }

    private static bool ArraysSemanticallyEqual(
        JsonElement leftArray,
        JsonElement rightArray,
        string? propertyName,
        string? ownerModelType)
    {
        if (string.Equals(propertyName, "allowedRoles", StringComparison.OrdinalIgnoreCase))
        {
            var leftRoles = leftArray
                .EnumerateArray()
                .Select(item => item.ValueKind == JsonValueKind.String ? item.GetString() : item.GetRawText())
                .Where(role => !string.IsNullOrWhiteSpace(role))
                .ToHashSet(StringComparer.OrdinalIgnoreCase);
            var rightRoles = rightArray
                .EnumerateArray()
                .Select(item => item.ValueKind == JsonValueKind.String ? item.GetString() : item.GetRawText())
                .Where(role => !string.IsNullOrWhiteSpace(role))
                .ToHashSet(StringComparer.OrdinalIgnoreCase);
            return leftRoles.SetEquals(rightRoles);
        }

        var compareById =
            (string.Equals(propertyName, "objects", StringComparison.OrdinalIgnoreCase) &&
             string.Equals(ownerModelType, MicroflowObjectCollectionModelType, StringComparison.OrdinalIgnoreCase)) ||
            (string.Equals(propertyName, "flows", StringComparison.OrdinalIgnoreCase) &&
             string.Equals(ownerModelType, MicroflowModelType, StringComparison.OrdinalIgnoreCase));

        if (compareById &&
            TryBuildObjectMapById(leftArray, out var leftMap) &&
            TryBuildObjectMapById(rightArray, out var rightMap))
        {
            if (leftMap.Count != rightMap.Count)
            {
                return false;
            }

            foreach (var (itemId, leftItem) in leftMap)
            {
                if (!rightMap.TryGetValue(itemId, out var rightItem))
                {
                    return false;
                }

                if (!ElementsSemanticallyEqual(leftItem, rightItem, ownerModelType: ownerModelType))
                {
                    return false;
                }
            }

            return true;
        }

        var leftItems = leftArray.EnumerateArray().ToArray();
        var rightItems = rightArray.EnumerateArray().ToArray();
        if (leftItems.Length != rightItems.Length)
        {
            return false;
        }

        for (var index = 0; index < leftItems.Length; index++)
        {
            if (!ElementsSemanticallyEqual(leftItems[index], rightItems[index], ownerModelType: ownerModelType))
            {
                return false;
            }
        }

        return true;
    }

    private static bool TryBuildObjectMapById(
        JsonElement arrayElement,
        out Dictionary<string, JsonElement> objectMap)
    {
        objectMap = new Dictionary<string, JsonElement>(StringComparer.OrdinalIgnoreCase);
        foreach (var item in arrayElement.EnumerateArray())
        {
            if (item.ValueKind != JsonValueKind.Object)
            {
                objectMap.Clear();
                return false;
            }

            var itemId = TryReadStringProperty(item, "$ID");
            if (string.IsNullOrWhiteSpace(itemId))
            {
                objectMap.Clear();
                return false;
            }

            objectMap[itemId] = item;
        }

        return true;
    }

    private static bool ShouldIgnorePropertyForSemanticDiff(string? modelType, string propertyName)
    {
        if (string.IsNullOrWhiteSpace(propertyName))
        {
            return false;
        }

        if (string.Equals(propertyName, "objectCollection", StringComparison.OrdinalIgnoreCase) &&
            string.Equals(modelType, MicroflowModelType, StringComparison.OrdinalIgnoreCase))
        {
            // Object collection order and layout pointers are noisy; semantic graph diff is captured elsewhere.
            return true;
        }

        return IsMicroflowRelatedModelType(modelType) &&
               LayoutOnlyPropertyNames.Contains(propertyName);
    }

    private static bool ShouldIgnorePropertyForDetailSummary(string? modelType, string propertyName)
    {
        return string.Equals(propertyName, "allowedRoles", StringComparison.OrdinalIgnoreCase) &&
               string.Equals(modelType, PageModelType, StringComparison.OrdinalIgnoreCase);
    }

    private static bool IsMicroflowRelatedModelType(string? modelType) =>
        !string.IsNullOrWhiteSpace(modelType) &&
        modelType.StartsWith("Microflows$", StringComparison.OrdinalIgnoreCase);

    private static string? BuildModificationDetails(JsonElement previousValue, JsonElement currentValue)
    {
        if (previousValue.ValueKind != JsonValueKind.Object || currentValue.ValueKind != JsonValueKind.Object)
        {
            return null;
        }

        var resourceModelType =
            TryReadStringProperty(currentValue, "$Type") ??
            TryReadStringProperty(previousValue, "$Type");

        var previousProperties = previousValue
            .EnumerateObject()
            .Where(property =>
                !ShouldIgnorePropertyForSemanticDiff(resourceModelType, property.Name) &&
                !ShouldIgnorePropertyForDetailSummary(resourceModelType, property.Name))
            .ToDictionary(property => property.Name, property => property.Value, StringComparer.Ordinal);
        var currentProperties = currentValue
            .EnumerateObject()
            .Where(property =>
                !ShouldIgnorePropertyForSemanticDiff(resourceModelType, property.Name) &&
                !ShouldIgnorePropertyForDetailSummary(resourceModelType, property.Name))
            .ToDictionary(property => property.Name, property => property.Value, StringComparer.Ordinal);
        var detailParts = new List<string>();

        foreach (var (propertyName, currentPropertyValue) in currentProperties)
        {
            if (IgnoredDetailFields.Contains(propertyName))
            {
                continue;
            }

            if (!previousProperties.TryGetValue(propertyName, out var previousPropertyValue))
            {
                detailParts.Add($"{propertyName} added");
                continue;
            }

            if (!ElementsSemanticallyEqual(previousPropertyValue, currentPropertyValue, propertyName, resourceModelType))
            {
                detailParts.Add(DescribePropertyChange(propertyName, previousPropertyValue, currentPropertyValue));
            }
        }

        foreach (var propertyName in previousProperties.Keys)
        {
            if (IgnoredDetailFields.Contains(propertyName))
            {
                continue;
            }

            if (!currentProperties.ContainsKey(propertyName))
            {
                detailParts.Add($"{propertyName} removed");
            }
        }

        if (detailParts.Count == 0)
        {
            return null;
        }

        const int maxParts = 4;
        var visible = detailParts.Take(maxParts).ToList();
        var summary = string.Join("; ", visible);
        var remaining = detailParts.Count - visible.Count;

        if (remaining > 0)
        {
            summary = $"{summary}; +{remaining} more";
        }

        return summary;
    }

    private static string? MergeDetailTexts(string? primary, string? secondary)
    {
        var parts = new List<string>();
        if (!string.IsNullOrWhiteSpace(primary))
        {
            parts.Add(primary.Trim());
        }

        if (!string.IsNullOrWhiteSpace(secondary))
        {
            var trimmedSecondary = secondary.Trim();
            if (!parts.Contains(trimmedSecondary, StringComparer.Ordinal))
            {
                parts.Add(trimmedSecondary);
            }
        }

        return parts.Count == 0 ? null : string.Join("; ", parts);
    }

    private static string? TryReadStringProperty(JsonElement element, string propertyName)
    {
        foreach (var property in element.EnumerateObject())
        {
            if (!string.Equals(property.Name, propertyName, StringComparison.OrdinalIgnoreCase))
            {
                continue;
            }

            if (property.Value.ValueKind == JsonValueKind.String)
            {
                return property.Value.GetString();
            }

            if (property.Value.ValueKind == JsonValueKind.Number ||
                property.Value.ValueKind == JsonValueKind.True ||
                property.Value.ValueKind == JsonValueKind.False)
            {
                return property.Value.GetRawText();
            }
        }

        return null;
    }

    private static bool TryReadBooleanProperty(JsonElement element, string propertyName, out bool value)
    {
        value = default;
        if (!TryReadProperty(element, propertyName, out var propertyValue))
        {
            return false;
        }

        if (propertyValue.ValueKind is JsonValueKind.True or JsonValueKind.False)
        {
            value = propertyValue.GetBoolean();
            return true;
        }

        if (propertyValue.ValueKind == JsonValueKind.String &&
            bool.TryParse(propertyValue.GetString(), out var parsed))
        {
            value = parsed;
            return true;
        }

        return false;
    }

    private static bool IsNonPersistentEntity(JsonElement entityElement)
    {
        if (TryReadBooleanProperty(entityElement, "persistable", out var persistable))
        {
            return !persistable;
        }

        if (TryReadProperty(entityElement, "generalization", out var generalizationElement) &&
            generalizationElement.ValueKind == JsonValueKind.Object &&
            TryReadBooleanProperty(generalizationElement, "persistable", out var generalizedPersistable))
        {
            return !generalizedPersistable;
        }

        return false;
    }

    private static bool ElementsEqual(JsonElement left, JsonElement right)
    {
        if (left.ValueKind != right.ValueKind)
        {
            return false;
        }

        switch (left.ValueKind)
        {
            case JsonValueKind.Object:
            {
                var leftProperties = left.EnumerateObject().ToDictionary(property => property.Name, property => property.Value, StringComparer.Ordinal);
                var rightProperties = right.EnumerateObject().ToDictionary(property => property.Name, property => property.Value, StringComparer.Ordinal);

                if (leftProperties.Count != rightProperties.Count)
                {
                    return false;
                }

                foreach (var (name, leftValue) in leftProperties)
                {
                    if (!rightProperties.TryGetValue(name, out var rightValue))
                    {
                        return false;
                    }

                    if (!ElementsEqual(leftValue, rightValue))
                    {
                        return false;
                    }
                }

                return true;
            }

            case JsonValueKind.Array:
            {
                var leftItems = left.EnumerateArray().ToArray();
                var rightItems = right.EnumerateArray().ToArray();
                if (leftItems.Length != rightItems.Length)
                {
                    return false;
                }

                for (var index = 0; index < leftItems.Length; index++)
                {
                    if (!ElementsEqual(leftItems[index], rightItems[index]))
                    {
                        return false;
                    }
                }

                return true;
            }

            case JsonValueKind.String:
                return string.Equals(left.GetString(), right.GetString(), StringComparison.Ordinal);

            case JsonValueKind.Number:
                return string.Equals(left.GetRawText(), right.GetRawText(), StringComparison.Ordinal);

            case JsonValueKind.True:
            case JsonValueKind.False:
                return left.GetBoolean() == right.GetBoolean();

            case JsonValueKind.Null:
            case JsonValueKind.Undefined:
                return true;

            default:
                return string.Equals(left.GetRawText(), right.GetRawText(), StringComparison.Ordinal);
        }
    }

    private static string DescribePropertyChange(string propertyName, JsonElement previous, JsonElement current)
    {
        if (previous.ValueKind == JsonValueKind.Array && current.ValueKind == JsonValueKind.Array)
        {
            var previousCount = previous.GetArrayLength();
            var currentCount = current.GetArrayLength();
            if (previousCount != currentCount)
            {
                return $"{propertyName} count {previousCount}->{currentCount}";
            }

            return $"{propertyName} entries updated";
        }

        if (IsScalar(previous.ValueKind) && IsScalar(current.ValueKind))
        {
            var previousText = FormatScalar(previous);
            var currentText = FormatScalar(current);
            if (!string.Equals(previousText, currentText, StringComparison.Ordinal))
            {
                return $"{propertyName} {previousText}->{currentText}";
            }
        }

        return $"{propertyName} updated";
    }

    private static bool IsScalar(JsonValueKind kind) =>
        kind is JsonValueKind.String or JsonValueKind.Number or JsonValueKind.True or JsonValueKind.False or JsonValueKind.Null;

    private static string FormatScalar(JsonElement value)
    {
        var text = value.ValueKind switch
        {
            JsonValueKind.String => value.GetString() ?? "null",
            JsonValueKind.True => "true",
            JsonValueKind.False => "false",
            JsonValueKind.Null => "null",
            _ => value.GetRawText(),
        };

        const int maxLength = 28;
        if (text.Length > maxLength)
        {
            text = $"{text[..maxLength]}...";
        }

        return text.Replace("\r", " ").Replace("\n", " ");
    }

    private static JsonDocument ParseDump(string path)
    {
        var text = File.ReadAllText(path);
        if (text.Length > 0 && text[0] == '\uFEFF')
        {
            text = text[1..];
        }

        return JsonDocument.Parse(text);
    }

    private sealed class DumpSnapshot
    {
        public Dictionary<string, JsonElement> ObjectsById { get; } = new(StringComparer.OrdinalIgnoreCase);
        public Dictionary<string, string> ParentById { get; } = new(StringComparer.OrdinalIgnoreCase);
        public Dictionary<string, ResourceDescriptor> ResourcesById { get; } = new(StringComparer.OrdinalIgnoreCase);
    }

    private sealed class MutableResourceChange
    {
        public MutableResourceChange(string changeType, ResourceDescriptor descriptor)
        {
            ChangeType = changeType;
            Descriptor = descriptor;
        }

        public string ChangeType { get; set; }

        public ResourceDescriptor Descriptor { get; set; }

        public string? DirectDetails { get; set; }

        public NestedChangeCounter NestedChanges { get; } = new();
    }

    private sealed class NestedChangeCounter
    {
        public int AddedCount { get; private set; }

        public int ModifiedCount { get; private set; }

        public int DeletedCount { get; private set; }

        public void Increment(string changeType)
        {
            switch (changeType)
            {
                case "Added":
                    AddedCount++;
                    break;
                case "Deleted":
                    DeletedCount++;
                    break;
                default:
                    ModifiedCount++;
                    break;
            }
        }

        public string? ToDetailText()
        {
            var total = AddedCount + ModifiedCount + DeletedCount;
            if (total <= 0)
            {
                return null;
            }

            var parts = new List<string>();
            if (AddedCount > 0)
            {
                parts.Add($"{AddedCount} added");
            }

            if (ModifiedCount > 0)
            {
                parts.Add($"{ModifiedCount} modified");
            }

            if (DeletedCount > 0)
            {
                parts.Add($"{DeletedCount} deleted");
            }

            return $"{total} nested change{(total == 1 ? string.Empty : "s")} ({string.Join(", ", parts)})";
        }
    }

